window.BILARA = window.BILARA || {};
window.BILARA["dn14"] = window.BILARA["dn14"] || {};
window.BILARA["dn14"]["vi"] = {
  "dn14:0.1": "Trường Bộ Kinh 14 ",
  "dn14:0.2": "Kinh Đại Bổn ",
  "dn14:1.0": "1. Bàn về các đời sống quá khứ ",
  "dn14:1.1.1": "Như vầy tôi nghe—",
  "dn14:1.1.2": "Một thời Thế Tôn trú tại Sāvatthi, ở rừng Jeta, vườn của ông Anāthapiṇḍika, trong am thất Karerī. ",
  "dn14:1.1.3": "Lúc bấy giờ, sau buổi đi khất thực về, nhiều vị Tỳ Kheo tụ họp lại ngồi trong giảng đường Karerī, và khởi lên câu chuyện về các đời sống quá khứ: ",
  "dn14:1.1.4": "“Đây là đời sống quá khứ, đây là đời sống quá khứ.” ",
  "dn14:1.2.1": "Với thiên nhĩ giới thanh tịnh vượt qua tầm tai người thường, Thế Tôn nghe được câu chuyện của các Tỳ Kheo ấy. ",
  "dn14:1.2.2": "Rồi Thế Tôn đứng dậy khỏi chỗ ngồi, đi đến giảng đường Karerī; sau khi đến, Ngài ngồi xuống chỗ đã được soạn sẵn, ngồi xuống Thế Tôn hỏi các Tỳ Kheo: ",
  "dn14:1.2.3": "“Này các Tỳ Kheo, hiện giờ các ông đang ngồi bàn chuyện gì, và câu chuyện đang nói dở đó là gì?” ",
  "dn14:1.2.4": "Khi được nói vậy, các Tỳ Kheo ấy bạch Thế Tôn rằng: ",
  "dn14:1.2.5": "“Bạch Thế Tôn, sau buổi đi khất thực về, chúng con tụ họp lại ngồi trong giảng đường Karerī, và khởi lên câu chuyện về các đời sống quá khứ: ",
  "dn14:1.2.6": "‘Đây là đời sống quá khứ, đây là đời sống quá khứ.’ ",
  "dn14:1.2.7": "Bạch Thế Tôn, đó là câu chuyện của chúng con đang nói dở. Lúc ấy Thế Tôn đến.” ",
  "dn14:1.3.1": "“Này các Tỳ Kheo, các ông có muốn nghe bài pháp về các đời sống quá khứ không?” ",
  "dn14:1.3.2": "“Bạch Thế Tôn, đã đến giờ; bạch Thiện Thệ, đã đến giờ; ",
  "dn14:1.3.3": "mong Thế Tôn thuyết bài pháp về các đời sống quá khứ, sau khi nghe Thế Tôn, các Tỳ Kheo sẽ thọ trì.” ",
  "dn14:1.3.4": "“Vậy thì, này các Tỳ Kheo, hãy lắng nghe, khéo tác ý, Ta sẽ nói.” ",
  "dn14:1.3.5": "“Thưa vâng, Thế Tôn”, các Tỳ Kheo ấy vâng lời Thế Tôn. ",
  "dn14:1.3.6": "Thế Tôn đã nói: ",
  "dn14:1.4.1": "“Này các Tỳ Kheo, cách đây chín mươi mốt kiếp, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời. ",
  "dn14:1.4.2": "Này các Tỳ Kheo, cách đây ba mươi mốt kiếp, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời. ",
  "dn14:1.4.3": "Cũng trong ba mươi mốt kiếp ấy, này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời. ",
  "dn14:1.4.4": "Trong kiếp hiền này, này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:1.4.5": "Trong kiếp hiền này, này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:1.4.6": "Trong kiếp hiền này, này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:1.4.7": "Trong kiếp hiền này, này các Tỳ Kheo, nay Ta là bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:1.5.1": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:1.5.2": "Này các Tỳ Kheo, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:1.5.3": "Này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:1.5.4": "Này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Bà-la-môn, sinh trong gia đình Bà-la-môn. ",
  "dn14:1.5.5": "Này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Bà-la-môn, sinh trong gia đình Bà-la-môn. ",
  "dn14:1.5.6": "Này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Bà-la-môn, sinh trong gia đình Bà-la-môn. ",
  "dn14:1.5.7": "Nay Ta, này các Tỳ Kheo, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:1.6.1": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña. ",
  "dn14:1.6.2": "Này các Tỳ Kheo, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña. ",
  "dn14:1.6.3": "Này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña. ",
  "dn14:1.6.4": "Này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Kassapa. ",
  "dn14:1.6.5": "Này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Kassapa. ",
  "dn14:1.6.6": "Này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Kassapa. ",
  "dn14:1.6.7": "Nay Ta, này các Tỳ Kheo, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Gotama. ",
  "dn14:1.7.1": "Này các Tỳ Kheo, thọ mạng của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác là tám mươi ngàn năm. ",
  "dn14:1.7.2": "Này các Tỳ Kheo, thọ mạng của Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác là bảy mươi ngàn năm. ",
  "dn14:1.7.3": "Này các Tỳ Kheo, thọ mạng của Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác là sáu mươi ngàn năm. ",
  "dn14:1.7.4": "Này các Tỳ Kheo, thọ mạng của Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác là bốn mươi ngàn năm. ",
  "dn14:1.7.5": "Này các Tỳ Kheo, thọ mạng của Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác là ba mươi ngàn năm. ",
  "dn14:1.7.6": "Này các Tỳ Kheo, thọ mạng của Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác là hai mươi ngàn năm. ",
  "dn14:1.7.7": "Nay thọ mạng của Ta, này các Tỳ Kheo, ngắn ngủi, ít ỏi, chóng qua; ai sống lâu thì cũng chỉ một trăm năm hoặc hơn chút ít. ",
  "dn14:1.8.1": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Pāṭali. ",
  "dn14:1.8.2": "Này các Tỳ Kheo, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Puṇḍarīka. ",
  "dn14:1.8.3": "Này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Sāla. ",
  "dn14:1.8.4": "Này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Sirīsa. ",
  "dn14:1.8.5": "Này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Udumbara. ",
  "dn14:1.8.6": "Này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Nigrodha. ",
  "dn14:1.8.7": "Nay Ta, này các Tỳ Kheo, bậc A-la-hán, Chánh Đẳng Giác, chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Assattha. ",
  "dn14:1.9.1": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Khaṇḍa và Tissa là đệ tử tối thượng, thù thắng. ",
  "dn14:1.9.2": "Này các Tỳ Kheo, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Abhibhū và Sambhava là đệ tử tối thượng, thù thắng. ",
  "dn14:1.9.3": "Này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Soṇa và Uttara là đệ tử tối thượng, thù thắng. ",
  "dn14:1.9.4": "Này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Vidhura và Sañjīva là đệ tử tối thượng, thù thắng. ",
  "dn14:1.9.5": "Này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Bhiyyosa và Uttara là đệ tử tối thượng, thù thắng. ",
  "dn14:1.9.6": "Này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Tissa và Bhāradvāja là đệ tử tối thượng, thù thắng. ",
  "dn14:1.9.7": "Nay Ta, này các Tỳ Kheo, có hai vị đệ tử tên Sāriputta và Moggallāna là đệ tử tối thượng, thù thắng. ",
  "dn14:1.10.1": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có ba lần hội họp đệ tử. Một lần hội họp có sáu triệu tám trăm ngàn Tỳ Kheo, một lần hội họp có một trăm ngàn Tỳ Kheo, một lần hội họp có tám mươi ngàn Tỳ Kheo. Này các Tỳ Kheo, đây là ba lần hội họp đệ tử của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.10.2": "Này các Tỳ Kheo, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác có ba lần hội họp đệ tử. Một lần hội họp có một trăm ngàn Tỳ Kheo, một lần hội họp có tám mươi ngàn Tỳ Kheo, một lần hội họp có bảy mươi ngàn Tỳ Kheo. Này các Tỳ Kheo, đây là ba lần hội họp đệ tử của Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.10.3": "Này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác có ba lần hội họp đệ tử. Một lần hội họp có tám mươi ngàn Tỳ Kheo, một lần hội họp có bảy mươi ngàn Tỳ Kheo, một lần hội họp có sáu mươi ngàn Tỳ Kheo. Này các Tỳ Kheo, đây là ba lần hội họp đệ tử của Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.10.4": "Này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác có một lần hội họp đệ tử gồm bốn mươi ngàn Tỳ Kheo. Này các Tỳ Kheo, đây là một lần hội họp đệ tử của Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.10.5": "Này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác có một lần hội họp đệ tử gồm ba mươi ngàn Tỳ Kheo. Này các Tỳ Kheo, đây là một lần hội họp đệ tử của Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.10.6": "Này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác có một lần hội họp đệ tử gồm hai mươi ngàn Tỳ Kheo. Này các Tỳ Kheo, đây là một lần hội họp đệ tử của Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.10.7": "Nay Ta, này các Tỳ Kheo, có một lần hội họp đệ tử gồm một ngàn hai trăm năm mươi Tỳ Kheo. Này các Tỳ Kheo, đây là một lần hội họp đệ tử của Ta, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.11.1": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Asoka là thị giả, thị giả tối thượng. ",
  "dn14:1.11.2": "Này các Tỳ Kheo, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Khemaṅkara là thị giả, thị giả tối thượng. ",
  "dn14:1.11.3": "Này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Upasanta là thị giả, thị giả tối thượng. ",
  "dn14:1.11.4": "Này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Buddhija là thị giả, thị giả tối thượng. ",
  "dn14:1.11.5": "Này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Sotthija là thị giả, thị giả tối thượng. ",
  "dn14:1.11.6": "Này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Sabbamitta là thị giả, thị giả tối thượng. ",
  "dn14:1.11.7": "Nay Ta, này các Tỳ Kheo, có vị Tỳ Kheo tên Ānanda là thị giả, thị giả tối thượng. ",
  "dn14:1.12.1": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có cha là vua tên Bandhuma. ",
  "dn14:1.12.2": "Mẹ sinh ra Ngài là hoàng hậu tên Bandhumatī. ",
  "dn14:1.12.3": "Kinh đô của vua Bandhuma là thành Bandhumatī. ",
  "dn14:1.12.4": "Này các Tỳ Kheo, Thế Tôn Sikhī, bậc A-la-hán, Chánh Đẳng Giác có cha là vua tên Aruṇa. ",
  "dn14:1.12.5": "Mẹ sinh ra Ngài là hoàng hậu tên Pabhāvatī. ",
  "dn14:1.12.6": "Kinh đô của vua Aruṇa là thành Aruṇavatī. ",
  "dn14:1.12.7": "Này các Tỳ Kheo, Thế Tôn Vessabhū, bậc A-la-hán, Chánh Đẳng Giác có cha là vua tên Suppatīta. ",
  "dn14:1.12.8": "Mẹ sinh ra Ngài là hoàng hậu tên Vassavatī. ",
  "dn14:1.12.9": "Kinh đô của vua Suppatīta là thành Anoma. ",
  "dn14:1.12.10": "Này các Tỳ Kheo, Thế Tôn Kakusandha, bậc A-la-hán, Chánh Đẳng Giác có cha là Bà-la-môn tên Aggidatta. ",
  "dn14:1.12.11": "Mẹ sinh ra Ngài là bà Bà-la-môn tên Visākhā. ",
  "dn14:1.12.12": "Này các Tỳ Kheo, vào thời ấy có vị vua tên Khema. ",
  "dn14:1.12.13": "Kinh đô của vua Khema là thành Khemavatī. ",
  "dn14:1.12.14": "Này các Tỳ Kheo, Thế Tôn Koṇāgamana, bậc A-la-hán, Chánh Đẳng Giác có cha là Bà-la-môn tên Yaññadatta. ",
  "dn14:1.12.15": "Mẹ sinh ra Ngài là bà Bà-la-môn tên Uttarā. ",
  "dn14:1.12.16": "Này các Tỳ Kheo, vào thời ấy có vị vua tên Sobha. ",
  "dn14:1.12.17": "Kinh đô của vua Sobha là thành Sobhavatī. ",
  "dn14:1.12.18": "Này các Tỳ Kheo, Thế Tôn Kassapa, bậc A-la-hán, Chánh Đẳng Giác có cha là Bà-la-môn tên Brahmadatta. ",
  "dn14:1.12.19": "Mẹ sinh ra Ngài là bà Bà-la-môn tên Dhanavatī. ",
  "dn14:1.12.20": "Này các Tỳ Kheo, vào thời ấy có vị vua tên Kikī. ",
  "dn14:1.12.21": "Kinh đô của vua Kikī là thành Bārāṇasī. ",
  "dn14:1.12.22": "Nay Ta, này các Tỳ Kheo, có cha là vua tên Suddhodana. ",
  "dn14:1.12.23": "Mẹ sinh ra Ta là hoàng hậu tên Māyā. ",
  "dn14:1.12.24": "Kinh đô là thành Kapilavatthu.” ",
  "dn14:1.12.25": "Thế Tôn đã nói như vậy. ",
  "dn14:1.12.26": "Sau khi nói xong, Thiện Thệ đứng dậy khỏi chỗ ngồi và đi vào tinh xá. ",
  "dn14:1.13.1": "Rồi ngay sau khi Thế Tôn vừa đi khỏi, các Tỳ Kheo ấy khởi lên câu chuyện này: ",
  "dn14:1.13.2": "“Thật tuyệt vời thay, chư hiền, thật hy hữu thay, chư hiền, đại thần lực và đại oai lực của Như Lai. ",
  "dn14:1.13.3": "Vì Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau; Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ",
  "dn14:1.13.4": "‘Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy.’” ",
  "dn14:1.13.5": "“Chư hiền, phải chăng đây là pháp giới mà Như Lai đã khéo thông đạt, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ‘Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy’, ",
  "dn14:1.13.6": "hay chư thiên báo cho Như Lai biết điều ấy, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ‘Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy’?” ",
  "dn14:1.13.7": "Đây là câu chuyện đang nói dở của các Tỳ Kheo ấy. ",
  "dn14:1.14.1": "Rồi Thế Tôn, vào buổi chiều, xuất khỏi thiền tĩnh mịch, đi đến giảng đường Karerī; sau khi đến, Ngài ngồi xuống chỗ đã được soạn sẵn. ",
  "dn14:1.14.2": "Ngồi xuống, Thế Tôn hỏi các Tỳ Kheo: ",
  "dn14:1.14.3": "“Này các Tỳ Kheo, hiện giờ các ông đang ngồi bàn chuyện gì, và câu chuyện đang nói dở đó là gì?” ",
  "dn14:1.14.4": "Khi được nói vậy, các Tỳ Kheo ấy bạch Thế Tôn rằng: ",
  "dn14:1.14.5": "“Bạch Thế Tôn, ngay sau khi Thế Tôn vừa đi khỏi, câu chuyện này khởi lên nơi chúng con: ",
  "dn14:1.14.6": "‘Thật tuyệt vời thay, chư hiền, thật hy hữu thay, chư hiền, đại thần lực và đại oai lực của Như Lai. ",
  "dn14:1.14.7": "Vì Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ",
  "dn14:1.14.8": "“Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy.” ",
  "dn14:1.14.9": "Chư hiền, phải chăng đây là pháp giới mà Như Lai đã khéo thông đạt, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ",
  "dn14:1.14.10": "“Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy.” ",
  "dn14:1.14.11": "Hay chư thiên báo cho Như Lai biết điều ấy, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ",
  "dn14:1.14.12": "“Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy”?’ ",
  "dn14:1.14.13": "Bạch Thế Tôn, đó là câu chuyện của chúng con đang nói dở, lúc ấy Thế Tôn đến.” ",
  "dn14:1.15.1": "“Này các Tỳ Kheo, đây chính là pháp giới mà Như Lai đã khéo thông đạt, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ",
  "dn14:1.15.2": "‘Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy.’ ",
  "dn14:1.15.3": "Chư thiên cũng báo cho Như Lai biết điều ấy, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ",
  "dn14:1.15.4": "‘Các Thế Tôn ấy có dòng sinh như vậy, có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy.’ ",
  "dn14:1.15.5": "Này các Tỳ Kheo, các ông có muốn nghe thêm bài pháp về các đời sống quá khứ không?” ",
  "dn14:1.15.6": "“Bạch Thế Tôn, đã đến giờ; bạch Thiện Thệ, đã đến giờ; ",
  "dn14:1.15.7": "mong Thế Tôn thuyết thêm bài pháp về các đời sống quá khứ, sau khi nghe Thế Tôn, các Tỳ Kheo sẽ thọ trì.” ",
  "dn14:1.15.8": "“Vậy thì, này các Tỳ Kheo, hãy lắng nghe, khéo tác ý, Ta sẽ nói.” ",
  "dn14:1.15.9": "“Thưa vâng, Thế Tôn”, các Tỳ Kheo ấy vâng lời Thế Tôn. ",
  "dn14:1.15.10": "Thế Tôn đã nói: ",
  "dn14:1.16.1": "“Này các Tỳ Kheo, cách đây chín mươi mốt kiếp, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác xuất hiện ở đời. ",
  "dn14:1.16.2": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:1.16.3": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña. ",
  "dn14:1.16.4": "Này các Tỳ Kheo, thọ mạng của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác là tám mươi ngàn năm. ",
  "dn14:1.16.5": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Pāṭali. ",
  "dn14:1.16.6": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Khaṇḍa và Tissa là đệ tử tối thượng, thù thắng. ",
  "dn14:1.16.7": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có ba lần hội họp đệ tử. ",
  "dn14:1.16.8": "Một lần hội họp có sáu triệu tám trăm ngàn Tỳ Kheo, một lần hội họp có một trăm ngàn Tỳ Kheo, một lần hội họp có tám mươi ngàn Tỳ Kheo. ",
  "dn14:1.16.9": "Này các Tỳ Kheo, đây là ba lần hội họp đệ tử của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:1.16.10": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Asoka là thị giả, thị giả tối thượng. ",
  "dn14:1.16.11": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có cha là vua tên Bandhuma. ",
  "dn14:1.16.12": "Mẹ sinh ra Ngài là hoàng hậu tên Bandhumatī. ",
  "dn14:1.16.13": "Kinh đô của vua Bandhuma là thành Bandhumatī. ",
  "dn14:1.17.0": "2. Pháp thường của các vị Bồ-tát ",
  "dn14:1.17.1": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī từ cõi trời Đâu-suất mất, với chánh niệm tỉnh giác, nhập vào thai mẹ. ",
  "dn14:1.17.2": "Đây là pháp thường ở đây. ",
  "dn14:1.17.3": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát từ cõi trời Đâu-suất mất và nhập vào thai mẹ. ",
  "dn14:1.17.4": "Lúc ấy, trong thế giới với chư thiên, Ma vương, Phạm thiên, cùng các chúng Sa-môn, Bà-la-môn, trời và người, một hào quang rộng lớn vô lượng xuất hiện, vượt qua cả uy lực của chư thiên. ",
  "dn14:1.17.5": "Ngay cả các khoảng không gian giữa các thế giới, những nơi vô hạn không có chỗ che chắn, tăm tối, đen tối mịt mù, nơi ngay cả mặt trăng và mặt trời dù có đại thần lực, đại oai lực như vậy cũng không thể chiếu tới bằng ánh sáng, thì ngay cả nơi ấy cũng xuất hiện hào quang rộng lớn vô lượng, vượt qua cả uy lực của chư thiên. ",
  "dn14:1.17.6": "Những chúng sinh đã sinh ra ở đó, nhờ hào quang ấy cũng nhận thấy được lẫn nhau: ‘Quý vị ơi, thì ra cũng có những chúng sinh khác sinh ra ở đây.’ ",
  "dn14:1.17.7": "Và cả mười ngàn thế giới đều rung động, chuyển động, chấn động. Một hào quang rộng lớn vô lượng xuất hiện ở đời, vượt qua cả uy lực của chư thiên. ",
  "dn14:1.17.8": "Đây là pháp thường ở đây. ",
  "dn14:1.17.9": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát đã nhập vào thai mẹ, có bốn vị Thiên tử đến bảo vệ bốn phương cho Bồ-tát: ‘Không ai, dù người hay phi nhân, được làm hại Bồ-tát hay mẹ của Bồ-tát.’ ",
  "dn14:1.17.10": "Đây là pháp thường ở đây. ",
  "dn14:1.18.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát đã nhập vào thai mẹ, mẹ của Bồ-tát tự nhiên trở thành người có giới hạnh, từ bỏ sát sinh, từ bỏ lấy của không cho, từ bỏ tà hạnh trong các dục, từ bỏ nói dối, từ bỏ uống rượu men và rượu nấu là nguyên nhân của phóng dật. ",
  "dn14:1.18.2": "Đây là pháp thường ở đây. ",
  "dn14:1.19.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát đã nhập vào thai mẹ, không có ý tưởng dục lạc nào khởi lên trong tâm mẹ của Bồ-tát đối với đàn ông, và mẹ của Bồ-tát không thể bị xâm phạm bởi bất cứ người đàn ông nào có lòng tham dục. ",
  "dn14:1.19.2": "Đây là pháp thường ở đây. ",
  "dn14:1.20.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát đã nhập vào thai mẹ, mẹ của Bồ-tát có được năm dục trưởng dưỡng. Bà được năm dục trưởng dưỡng thỏa mãn đầy đủ, tận hưởng. ",
  "dn14:1.20.2": "Đây là pháp thường ở đây. ",
  "dn14:1.21.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát đã nhập vào thai mẹ, không có bệnh hoạn nào khởi lên nơi mẹ của Bồ-tát. Mẹ của Bồ-tát sống an lạc, không mệt mỏi về thân, và mẹ của Bồ-tát nhìn thấy được Bồ-tát đang ở trong bụng, đầy đủ các bộ phận lớn nhỏ, không thiếu căn nào. ",
  "dn14:1.21.2": "Ví như, này các Tỳ Kheo, có viên ngọc lưu ly xinh đẹp, thuộc loại thượng hạng, có tám mặt, khéo mài giũa, trong suốt, sáng tỏ, không tì vết, đầy đủ mọi đặc tính. Một sợi dây xâu qua viên ngọc ấy, màu xanh, hay vàng, hay đỏ, hay trắng, hay xám nhạt. ",
  "dn14:1.21.3": "Một người có mắt cầm viên ngọc ấy trong tay rồi quan sát: ‘Đây là viên ngọc lưu ly xinh đẹp, thuộc loại thượng hạng, có tám mặt, khéo mài giũa, trong suốt, sáng tỏ, không tì vết, đầy đủ mọi đặc tính. Có sợi dây xâu qua màu xanh, hay vàng, hay đỏ, hay trắng, hay xám nhạt.’ ",
  "dn14:1.21.4": "Cũng vậy, này các Tỳ Kheo, khi Bồ-tát đã nhập vào thai mẹ, không có bệnh hoạn nào khởi lên nơi mẹ của Bồ-tát, mẹ của Bồ-tát sống an lạc, không mệt mỏi về thân, và mẹ của Bồ-tát nhìn thấy được Bồ-tát đang ở trong bụng, đầy đủ các bộ phận lớn nhỏ, không thiếu căn nào. ",
  "dn14:1.21.5": "Đây là pháp thường ở đây. ",
  "dn14:1.22.1": "Này các Tỳ Kheo, pháp thường là như vầy: bảy ngày sau khi sinh Bồ-tát, mẹ của Bồ-tát qua đời và được sinh lên cõi trời Đâu-suất. ",
  "dn14:1.22.2": "Đây là pháp thường ở đây. ",
  "dn14:1.23.1": "Này các Tỳ Kheo, pháp thường là như vầy: các phụ nữ khác mang thai trong bụng chín hay mười tháng rồi sinh, còn mẹ của Bồ-tát không sinh ra Bồ-tát như vậy. Mẹ của Bồ-tát mang Bồ-tát trong bụng đúng mười tháng rồi mới sinh. ",
  "dn14:1.23.2": "Đây là pháp thường ở đây. ",
  "dn14:1.24.1": "Này các Tỳ Kheo, pháp thường là như vầy: các phụ nữ khác ngồi hoặc nằm mà sinh, còn mẹ của Bồ-tát không sinh ra Bồ-tát như vậy. Mẹ của Bồ-tát sinh ra Bồ-tát khi đang đứng. ",
  "dn14:1.24.2": "Đây là pháp thường ở đây. ",
  "dn14:1.25.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát ra khỏi bụng mẹ, chư thiên đón nhận trước, rồi đến loài người. ",
  "dn14:1.25.2": "Đây là pháp thường ở đây. ",
  "dn14:1.26.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát ra khỏi bụng mẹ, Bồ-tát chưa chạm đất thì bốn vị Thiên tử đã đón nhận và đặt Bồ-tát trước mặt mẹ: ‘Thưa Hoàng hậu, xin hãy vui lòng; người con có đại thần lực đã sinh ra cho ngài.’ ",
  "dn14:1.26.2": "Đây là pháp thường ở đây. ",
  "dn14:1.27.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát ra khỏi bụng mẹ, Bồ-tát ra đời sạch sẽ, không bị vấy bẩn bởi nước ối, không bị vấy bẩn bởi máu mủ, không bị vấy bẩn bởi máu, không bị vấy bẩn bởi bất cứ chất dơ nào, thanh tịnh, sạch sẽ. ",
  "dn14:1.27.2": "Ví như, này các Tỳ Kheo, một viên ngọc báu đặt trên tấm vải Kāsika, viên ngọc báu không làm dơ tấm vải Kāsika, tấm vải Kāsika cũng không làm dơ viên ngọc báu. ",
  "dn14:1.27.3": "Vì sao vậy? ",
  "dn14:1.27.4": "Vì cả hai đều sạch. ",
  "dn14:1.27.5": "Cũng vậy, này các Tỳ Kheo, khi Bồ-tát ra khỏi bụng mẹ, Bồ-tát ra đời sạch sẽ, không bị vấy bẩn, không bị vấy bẩn bởi nước ối, không bị vấy bẩn bởi máu mủ, không bị vấy bẩn bởi máu, không bị vấy bẩn bởi bất cứ chất dơ nào, thanh tịnh, sạch sẽ. ",
  "dn14:1.27.6": "Đây là pháp thường ở đây. ",
  "dn14:1.28.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát ra khỏi bụng mẹ, hai dòng nước từ trên không hiện ra—một dòng lạnh, một dòng nóng, để tắm cho Bồ-tát và mẹ. ",
  "dn14:1.28.2": "Đây là pháp thường ở đây. ",
  "dn14:1.29.1": "Này các Tỳ Kheo, pháp thường là như vầy: Bồ-tát vừa mới sinh ra đã đứng vững trên hai chân, hướng về phía bắc, bước đi bảy bước với chiếc lọng trắng được che trên đầu, nhìn khắp mọi phương, và nói lời dũng mãnh: ‘Ta là bậc tối thượng ở đời, Ta là bậc cao quý nhất ở đời, Ta là bậc thù thắng nhất ở đời, đây là đời sống cuối cùng, nay không còn tái sinh nữa.’ ",
  "dn14:1.29.2": "Đây là pháp thường ở đây. ",
  "dn14:1.30.1": "Này các Tỳ Kheo, pháp thường là như vầy: khi Bồ-tát ra khỏi bụng mẹ, trong thế giới với chư thiên, Ma vương, Phạm thiên, cùng các chúng Sa-môn, Bà-la-môn, trời và người, một hào quang rộng lớn vô lượng xuất hiện, vượt qua cả uy lực của chư thiên. ",
  "dn14:1.30.2": "Ngay cả các khoảng không gian giữa các thế giới, những nơi vô hạn không có chỗ che chắn, tăm tối, đen tối mịt mù, nơi ngay cả mặt trăng và mặt trời dù có đại thần lực, đại oai lực như vậy cũng không thể chiếu tới bằng ánh sáng, thì ngay cả nơi ấy cũng xuất hiện hào quang rộng lớn vô lượng, vượt qua cả uy lực của chư thiên. ",
  "dn14:1.30.3": "Những chúng sinh đã sinh ra ở đó, nhờ hào quang ấy cũng nhận thấy được lẫn nhau: ‘Quý vị ơi, thì ra cũng có những chúng sinh khác sinh ra ở đây.’ ",
  "dn14:1.30.4": "Và cả mười ngàn thế giới đều rung động, chuyển động, chấn động, và một hào quang rộng lớn vô lượng xuất hiện ở đời, vượt qua cả uy lực của chư thiên. ",
  "dn14:1.30.5": "Đây là pháp thường ở đây. ",
  "dn14:1.31.0": "3. Ba mươi hai tướng đại nhân ",
  "dn14:1.31.1": "Này các Tỳ Kheo, khi Hoàng tử Vipassī ra đời, người ta báo cho vua Bandhuma biết: ",
  "dn14:1.31.2": "‘Thưa Đại vương, một hoàng tử đã sinh ra cho Đại vương, xin Đại vương hãy xem.’ ",
  "dn14:1.31.3": "Này các Tỳ Kheo, vua Bandhuma trông thấy Hoàng tử Vipassī, thấy rồi cho gọi các Bà-la-môn tinh thông tướng số đến và nói: ",
  "dn14:1.31.4": "‘Xin các Tôn giả Bà-la-môn tinh thông tướng số hãy xem hoàng tử.’ ",
  "dn14:1.31.5": "Này các Tỳ Kheo, các Bà-la-môn tinh thông tướng số trông thấy Hoàng tử Vipassī, thấy rồi thưa với vua Bandhuma: ",
  "dn14:1.31.6": "‘Thưa Đại vương, xin Đại vương hãy vui lòng, một người con có đại thần lực đã sinh ra cho ngài; Đại vương thật có lợi lộc, Đại vương thật khéo được, gia đình Đại vương có một người con như vậy ra đời. ",
  "dn14:1.31.7": "Thưa Đại vương, hoàng tử này đầy đủ ba mươi hai tướng đại nhân, mà ai có đủ ba mươi hai tướng ấy thì chỉ có hai con đường không khác. ",
  "dn14:1.31.8": "Nếu sống tại gia, sẽ trở thành Chuyển Luân Thánh Vương, đúng pháp, là vua pháp, bốn phương chiến thắng, đất nước an ổn, đầy đủ bảy báu. ",
  "dn14:1.31.9": "Bảy báu của vị ấy là: ",
  "dn14:1.31.10": "đó là—xe báu, voi báu, ngựa báu, ngọc báu, nữ báu, gia chủ báu, và báu thứ bảy là tướng quân báu. ",
  "dn14:1.31.11": "Vị ấy có hơn một ngàn người con trai là những bậc anh hùng, có hình dáng dũng mãnh, đập tan quân thù. ",
  "dn14:1.31.12": "Vị ấy chinh phục và cai trị trái đất này đến tận bờ biển, không dùng gậy gộc, không dùng vũ khí, bằng chánh pháp. ",
  "dn14:1.31.13": "Còn nếu xuất gia từ bỏ đời sống gia đình, sống đời không nhà, thì sẽ trở thành bậc A-la-hán, Chánh Đẳng Giác, vén màn vô minh ở đời. ",
  "dn14:1.32.1": "Thưa Đại vương, hoàng tử này đầy đủ ba mươi hai tướng đại nhân nào, mà ai có đủ các tướng ấy thì chỉ có hai con đường không khác. ",
  "dn14:1.32.2": "Nếu sống tại gia, sẽ trở thành Chuyển Luân Thánh Vương, đúng pháp, là vua pháp, bốn phương chiến thắng, đất nước an ổn, đầy đủ bảy báu. ",
  "dn14:1.32.3": "Bảy báu của vị ấy là: ",
  "dn14:1.32.4": "đó là—xe báu, voi báu, ngựa báu, ngọc báu, nữ báu, gia chủ báu, và báu thứ bảy là tướng quân báu. ",
  "dn14:1.32.5": "Vị ấy có hơn một ngàn người con trai là những bậc anh hùng, có hình dáng dũng mãnh, đập tan quân thù. ",
  "dn14:1.32.6": "Vị ấy chinh phục và cai trị trái đất này đến tận bờ biển, không dùng gậy gộc, không dùng vũ khí, bằng chánh pháp. ",
  "dn14:1.32.7": "Còn nếu xuất gia từ bỏ đời sống gia đình, sống đời không nhà, thì sẽ trở thành bậc A-la-hán, Chánh Đẳng Giác, vén màn vô minh ở đời. Thưa Đại vương, vì hoàng tử này có bàn chân đứng vững. Vì hoàng tử này có bàn chân đứng vững, nên đây là một tướng đại nhân của bậc đại nhân. ",
  "dn14:1.32.8": "Thưa Đại vương, dưới bàn chân của hoàng tử này có hình bánh xe với một ngàn căm, có vành, có trục, đầy đủ mọi đặc tính. Vì dưới bàn chân của hoàng tử này có hình bánh xe với một ngàn căm, có vành, có trục, đầy đủ mọi đặc tính, nên đây cũng là một tướng đại nhân của bậc đại nhân. ",
  "dn14:1.32.9": "Thưa Đại vương, hoàng tử này có gót chân rộng …(v.v.)… ",
  "dn14:1.32.10": "Thưa Đại vương, hoàng tử này có ngón tay ngón chân dài …(v.v.)… ",
  "dn14:1.32.11": "Thưa Đại vương, hoàng tử này có tay chân mềm mại …(v.v.)… ",
  "dn14:1.32.12": "Thưa Đại vương, hoàng tử này có tay chân có màng lưới …(v.v.)… ",
  "dn14:1.32.13": "Thưa Đại vương, hoàng tử này có mắt cá chân cao như vỏ ốc …(v.v.)… ",
  "dn14:1.32.14": "Thưa Đại vương, hoàng tử này có bắp chân như của con sơn dương …(v.v.)… ",
  "dn14:1.32.15": "Thưa Đại vương, hoàng tử này đứng thẳng không cúi xuống có thể sờ và xoa đầu gối bằng hai lòng bàn tay …(v.v.)… ",
  "dn14:1.32.16": "Thưa Đại vương, hoàng tử này có nam căn ẩn trong bao …(v.v.)… ",
  "dn14:1.32.17": "Thưa Đại vương, hoàng tử này có sắc vàng, da ánh như vàng ròng …(v.v.)… ",
  "dn14:1.32.18": "Thưa Đại vương, hoàng tử này có da mịn; nhờ da mịn mà bụi bẩn không bám vào thân …(v.v.)… ",
  "dn14:1.32.19": "Thưa Đại vương, hoàng tử này có lông mọc từng sợi; mỗi lỗ chân lông chỉ mọc một sợi lông …(v.v.)… ",
  "dn14:1.32.20": "Thưa Đại vương, hoàng tử này có lông mọc hướng lên; các sợi lông hướng lên, màu xanh đen như thuốc bôi mắt, cuộn xoắn, uốn tròn theo chiều bên phải …(v.v.)… ",
  "dn14:1.32.21": "Thưa Đại vương, hoàng tử này có thân hình thẳng như Phạm thiên …(v.v.)… ",
  "dn14:1.32.22": "Thưa Đại vương, hoàng tử này có bảy chỗ đầy đặn …(v.v.)… ",
  "dn14:1.32.23": "Thưa Đại vương, hoàng tử này có nửa thân trên như của sư tử …(v.v.)… ",
  "dn14:1.32.24": "Thưa Đại vương, hoàng tử này có khoảng giữa hai vai đầy đặn …(v.v.)… ",
  "dn14:1.32.25": "Thưa Đại vương, hoàng tử này tròn đầy như cây nigrodha, chiều cao thân thể bằng sải tay, sải tay bằng chiều cao thân thể …(v.v.)… ",
  "dn14:1.32.26": "Thưa Đại vương, hoàng tử này có vai tròn đều …(v.v.)… ",
  "dn14:1.32.27": "Thưa Đại vương, hoàng tử này có vị giác thượng hạng …(v.v.)… ",
  "dn14:1.32.28": "Thưa Đại vương, hoàng tử này có quai hàm như sư tử …(v.v.)… ",
  "dn14:1.32.29": "Thưa Đại vương, hoàng tử này có bốn mươi cái răng …(v.v.)… ",
  "dn14:1.32.30": "Thưa Đại vương, hoàng tử này có răng đều …(v.v.)… ",
  "dn14:1.32.31": "Thưa Đại vương, hoàng tử này có răng khít …(v.v.)… ",
  "dn14:1.32.32": "Thưa Đại vương, hoàng tử này có răng nanh rất trắng …(v.v.)… ",
  "dn14:1.32.33": "Thưa Đại vương, hoàng tử này có lưỡi rộng dài …(v.v.)… ",
  "dn14:1.32.34": "Thưa Đại vương, hoàng tử này có tiếng như Phạm thiên, nói như tiếng chim Ca-lăng-tần-già …(v.v.)… ",
  "dn14:1.32.35": "Thưa Đại vương, hoàng tử này có mắt rất xanh …(v.v.)… ",
  "dn14:1.32.36": "Thưa Đại vương, hoàng tử này có lông mi như lông bò cái …(v.v.)… ",
  "dn14:1.32.37": "Thưa Đại vương, hoàng tử này có lông trắng giữa hai chân mày, mềm như bông. Vì hoàng tử này có lông trắng giữa hai chân mày, mềm như bông, nên đây cũng là một tướng đại nhân của bậc đại nhân. ",
  "dn14:1.32.38": "Thưa Đại vương, hoàng tử này có đỉnh đầu nhô cao như khăn quấn. Vì hoàng tử này có đỉnh đầu nhô cao như khăn quấn, nên đây cũng là một tướng đại nhân của bậc đại nhân. ",
  "dn14:1.33.1": "Thưa Đại vương, hoàng tử này đầy đủ ba mươi hai tướng đại nhân này, mà ai có đủ các tướng ấy thì chỉ có hai con đường không khác. ",
  "dn14:1.33.2": "Nếu sống tại gia, sẽ trở thành Chuyển Luân Thánh Vương, đúng pháp, là vua pháp, bốn phương chiến thắng, đất nước an ổn, đầy đủ bảy báu. ",
  "dn14:1.33.3": "Bảy báu của vị ấy là: ",
  "dn14:1.33.4": "đó là—xe báu, voi báu, ngựa báu, ngọc báu, nữ báu, gia chủ báu, và báu thứ bảy là tướng quân báu. ",
  "dn14:1.33.5": "Vị ấy có hơn một ngàn người con trai là những bậc anh hùng, có hình dáng dũng mãnh, đập tan quân thù. ",
  "dn14:1.33.6": "Vị ấy chinh phục và cai trị trái đất này đến tận bờ biển, không dùng gậy gộc, không dùng vũ khí, bằng chánh pháp. ",
  "dn14:1.33.7": "Còn nếu xuất gia từ bỏ đời sống gia đình, sống đời không nhà, thì sẽ trở thành bậc A-la-hán, Chánh Đẳng Giác, vén màn vô minh ở đời.’ ",
  "dn14:1.33.8.0": "4. Ý nghĩa tên Vipassī ",
  "dn14:1.33.9": "Rồi này các Tỳ Kheo, vua Bandhuma ban y phục mới cho các Bà-la-môn tinh thông tướng số và làm thỏa mãn họ với mọi dục lạc. ",
  "dn14:1.34.1": "Rồi này các Tỳ Kheo, vua Bandhuma sắp xếp các vú nuôi cho Hoàng tử Vipassī. ",
  "dn14:1.34.2": "Người thì cho bú, người thì tắm, người thì bế, người thì ẵm trên tay. ",
  "dn14:1.34.3": "Này các Tỳ Kheo, khi Hoàng tử Vipassī đã sinh, người ta che lọng trắng trên đầu ngài cả ngày lẫn đêm: ",
  "dn14:1.34.4": "‘Đừng để lạnh, nóng, cỏ, bụi, hay sương làm hại ngài.’ ",
  "dn14:1.34.5": "Này các Tỳ Kheo, khi đã sinh, Hoàng tử Vipassī được nhiều người yêu mến, thương thích. ",
  "dn14:1.34.6": "Ví như, này các Tỳ Kheo, hoa sen xanh, hoa sen đỏ, hoa sen trắng được nhiều người yêu mến, thương thích; ",
  "dn14:1.34.7": "cũng vậy, này các Tỳ Kheo, Hoàng tử Vipassī được nhiều người yêu mến, thương thích. ",
  "dn14:1.34.8": "Ngài được chuyền từ tay người này sang tay người khác. ",
  "dn14:1.35.1": "Này các Tỳ Kheo, khi đã sinh, Hoàng tử Vipassī có giọng nói dịu dàng, có giọng nói khả ái, có giọng nói ngọt ngào, có giọng nói dễ mến. ",
  "dn14:1.35.2": "Ví như, này các Tỳ Kheo, ở núi Himavanta có loài chim tên là Karavīka có giọng nói dịu dàng, có giọng nói khả ái, có giọng nói ngọt ngào, có giọng nói dễ mến; ",
  "dn14:1.35.3": "cũng vậy, này các Tỳ Kheo, Hoàng tử Vipassī có giọng nói dịu dàng, có giọng nói khả ái, có giọng nói ngọt ngào, có giọng nói dễ mến. ",
  "dn14:1.36.1": "Này các Tỳ Kheo, khi đã sinh, Hoàng tử Vipassī có được thiên nhãn là quả của nghiệp, nhờ đó ngài có thể nhìn thấy chung quanh một do-tuần cả ngày lẫn đêm. ",
  "dn14:1.37.1": "Này các Tỳ Kheo, khi đã sinh, Hoàng tử Vipassī nhìn không chớp mắt giống như chư thiên cõi Ba Mươi Ba. ",
  "dn14:1.37.2": "Này các Tỳ Kheo, vì ‘Hoàng tử nhìn không chớp mắt’ nên tên ‘Vipassī, Vipassī’ (Quán Sát) được đặt cho Hoàng tử Vipassī. ",
  "dn14:1.37.3": "Rồi này các Tỳ Kheo, vua Bandhuma khi ngồi xử kiện, cho Hoàng tử Vipassī ngồi trên đùi, dạy cho con về việc xét xử. ",
  "dn14:1.37.4": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī ngồi trên đùi cha, xem xét kỹ lưỡng các vụ việc và phán quyết đúng đắn theo lẽ phải. ",
  "dn14:1.37.5": "Do Hoàng tử xem xét kỹ lưỡng các vụ việc và phán quyết đúng đắn theo lẽ phải, nên tên ‘Vipassī, Vipassī’ càng được khẳng định hơn đối với Hoàng tử Vipassī. ",
  "dn14:1.38.1": "Rồi này các Tỳ Kheo, vua Bandhuma cho xây ba cung điện cho Hoàng tử Vipassī—một dùng cho mùa mưa, một dùng cho mùa đông, một dùng cho mùa hè; ",
  "dn14:1.38.2": "và cung cấp năm dục trưởng dưỡng. ",
  "dn14:1.38.3": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī ở trong cung điện mùa mưa suốt bốn tháng, được các nữ nhạc công hầu hạ, không xuống khỏi cung điện. ",
  "dn14:1.38.4": "Hết tụng phần thứ nhất. ",
  "dn14:2.1.0": "5. Người già ",
  "dn14:2.1.1": "Rồi này các Tỳ Kheo, sau nhiều năm, nhiều trăm năm, nhiều ngàn năm, Hoàng tử Vipassī gọi người đánh xe: ",
  "dn14:2.1.2": "‘Này bạn đánh xe, hãy thắng những cỗ xe tốt, ta đi ra vườn ngự uyển để ngắm cảnh đẹp.’ ",
  "dn14:2.1.3": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, thắng những cỗ xe tốt rồi báo cho Hoàng tử Vipassī: ",
  "dn14:2.1.4": "‘Thưa Điện hạ, các cỗ xe tốt đã thắng xong, ",
  "dn14:2.1.5": "xin Điện hạ định giờ nào.’ ",
  "dn14:2.1.6": "Rồi này các Tỳ Kheo, Hoàng tử Vipassī leo lên cỗ xe tốt, cùng với các cỗ xe tốt đi ra vườn ngự uyển. ",
  "dn14:2.2.1": "Này các Tỳ Kheo, Hoàng tử Vipassī trên đường đi ra vườn ngự uyển, trông thấy một người già, lưng còng như mái hiên, chống gậy, run rẩy khi đi, yếu đuối, đã qua tuổi thanh xuân. ",
  "dn14:2.2.2": "Thấy vậy, ngài hỏi người đánh xe: ",
  "dn14:2.2.3": "‘Này bạn đánh xe, người ấy đã làm gì? ",
  "dn14:2.2.4": "Tóc của người ấy không giống như của người khác, thân của người ấy không giống như của người khác.’ ",
  "dn14:2.2.5": "‘Thưa Điện hạ, đó gọi là người già.’ ",
  "dn14:2.2.6": "‘Này bạn đánh xe, vì sao gọi là người già?’ ",
  "dn14:2.2.7": "‘Thưa Điện hạ, đó gọi là người già vì người ấy không còn sống được bao lâu nữa.’ ",
  "dn14:2.2.8": "‘Này bạn đánh xe, vậy ta cũng chịu pháp già, không vượt khỏi già chăng?’ ",
  "dn14:2.2.9": "‘Thưa Điện hạ, cả ngài và chúng tôi đều chịu pháp già, không vượt khỏi già.’ ",
  "dn14:2.2.10": "‘Vậy thì, này bạn đánh xe, hôm nay thôi vườn ngự uyển. Hãy cho xe quay về cung ngay từ đây.’ ",
  "dn14:2.2.11": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, cho xe quay về cung ngay từ đó. ",
  "dn14:2.2.12": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī trở về cung, khổ sầu, buồn bã, suy tư: ",
  "dn14:2.2.13": "‘Thật đáng chê trách cho sự sinh này, khi có sinh ra thì có già.’ ",
  "dn14:2.3.1": "Rồi này các Tỳ Kheo, vua Bandhuma cho gọi người đánh xe đến và hỏi: ",
  "dn14:2.3.2": "‘Này bạn đánh xe, Hoàng tử có vui vẻ ở vườn ngự uyển không? Này bạn đánh xe, Hoàng tử có hoan hỷ ở vườn ngự uyển không?’ ",
  "dn14:2.3.3": "‘Thưa Đại vương, Hoàng tử không vui vẻ ở vườn ngự uyển, thưa Đại vương, Hoàng tử không hoan hỷ ở vườn ngự uyển.’ ",
  "dn14:2.3.4": "‘Này bạn đánh xe, trên đường đi ra vườn ngự uyển, Hoàng tử đã trông thấy gì?’ ",
  "dn14:2.3.5": "‘Thưa Đại vương, trên đường đi ra vườn ngự uyển, Hoàng tử đã trông thấy một người già, lưng còng như mái hiên, chống gậy, run rẩy khi đi, yếu đuối, đã qua tuổi thanh xuân. ",
  "dn14:2.3.6": "Thấy vậy, Hoàng tử đã nói với tôi: ",
  "dn14:2.3.7": "“Này bạn đánh xe, người ấy đã làm gì, tóc của người ấy không giống như của người khác, thân của người ấy không giống như của người khác?” ",
  "dn14:2.3.8": "“Thưa Điện hạ, đó gọi là người già.” ",
  "dn14:2.3.9": "“Này bạn đánh xe, vì sao gọi là người già?” ",
  "dn14:2.3.10": "“Thưa Điện hạ, đó gọi là người già vì người ấy không còn sống được bao lâu nữa.” ",
  "dn14:2.3.11": "“Này bạn đánh xe, vậy ta cũng chịu pháp già, không vượt khỏi già chăng?” ",
  "dn14:2.3.12": "“Thưa Điện hạ, cả ngài và chúng tôi đều chịu pháp già, không vượt khỏi già.” ",
  "dn14:2.3.13": "“Vậy thì, này bạn đánh xe, hôm nay thôi vườn ngự uyển, hãy cho xe quay về cung ngay từ đây.” ",
  "dn14:2.3.14": "“Thưa vâng, Điện hạ”, thưa Đại vương, tôi vâng lời Hoàng tử Vipassī, cho xe quay về cung ngay từ đó. ",
  "dn14:2.3.15": "Thưa Đại vương, Hoàng tử trở về cung, khổ sầu, buồn bã, suy tư: ",
  "dn14:2.3.16": "“Thật đáng chê trách cho sự sinh này, khi có sinh ra thì có già.”’ ",
  "dn14:2.4.0": "6. Người bệnh ",
  "dn14:2.4.1": "Rồi này các Tỳ Kheo, vua Bandhuma khởi lên ý nghĩ: ",
  "dn14:2.4.2": "‘Chớ để Hoàng tử Vipassī không trị vì, chớ để Hoàng tử Vipassī xuất gia từ bỏ đời sống gia đình sống đời không nhà, chớ để lời nói của các Bà-la-môn tinh thông tướng số thành sự thật.’ ",
  "dn14:2.4.3": "Rồi này các Tỳ Kheo, vua Bandhuma cung cấp cho Hoàng tử Vipassī năm dục trưởng dưỡng càng nhiều hơn: ",
  "dn14:2.4.4": "‘Để Hoàng tử Vipassī trị vì, để Hoàng tử Vipassī không xuất gia từ bỏ đời sống gia đình sống đời không nhà, để lời nói của các Bà-la-môn tinh thông tướng số thành sai.’ ",
  "dn14:2.4.5": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī với năm dục trưởng dưỡng được cung cấp đầy đủ, thỏa mãn, tận hưởng. ",
  "dn14:2.5.1": "Rồi này các Tỳ Kheo, sau nhiều năm, Hoàng tử Vipassī …(v.v.)… ",
  "dn14:2.6.1": "Này các Tỳ Kheo, Hoàng tử Vipassī trên đường đi ra vườn ngự uyển, trông thấy một người bệnh, khổ sở, ốm nặng, nằm lăn trong phân và nước tiểu của chính mình, được người khác nâng dậy, được người khác đặt nằm xuống. ",
  "dn14:2.6.2": "Thấy vậy, ngài hỏi người đánh xe: ",
  "dn14:2.6.3": "‘Này bạn đánh xe, người ấy đã làm gì? ",
  "dn14:2.6.4": "Đôi mắt của người ấy không giống như của người khác, giọng nói của người ấy không giống như của người khác.’ ",
  "dn14:2.6.5": "‘Thưa Điện hạ, đó gọi là người bệnh.’ ",
  "dn14:2.6.6": "‘Này bạn đánh xe, vì sao gọi là người bệnh?’ ",
  "dn14:2.6.7": "‘Thưa Điện hạ, đó gọi là người bệnh, may ra người ấy có thể thoát khỏi bệnh ấy.’ ",
  "dn14:2.6.8": "‘Này bạn đánh xe, vậy ta cũng chịu pháp bệnh, không vượt khỏi bệnh chăng?’ ",
  "dn14:2.6.9": "‘Thưa Điện hạ, cả ngài và chúng tôi đều chịu pháp bệnh, không vượt khỏi bệnh.’ ",
  "dn14:2.6.10": "‘Vậy thì, này bạn đánh xe, hôm nay thôi vườn ngự uyển, hãy cho xe quay về cung ngay từ đây.’ ",
  "dn14:2.6.11": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, cho xe quay về cung ngay từ đó. ",
  "dn14:2.6.12": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī trở về cung, khổ sầu, buồn bã, suy tư: ",
  "dn14:2.6.13": "‘Thật đáng chê trách cho sự sinh này, khi có sinh ra thì có già, có bệnh.’ ",
  "dn14:2.7.1": "Rồi này các Tỳ Kheo, vua Bandhuma cho gọi người đánh xe đến và hỏi: ",
  "dn14:2.7.2": "‘Này bạn đánh xe, Hoàng tử có vui vẻ ở vườn ngự uyển không, này bạn đánh xe, Hoàng tử có hoan hỷ ở vườn ngự uyển không?’ ",
  "dn14:2.7.3": "‘Thưa Đại vương, Hoàng tử không vui vẻ ở vườn ngự uyển, thưa Đại vương, Hoàng tử không hoan hỷ ở vườn ngự uyển.’ ",
  "dn14:2.7.4": "‘Này bạn đánh xe, trên đường đi ra vườn ngự uyển, Hoàng tử đã trông thấy gì?’ ",
  "dn14:2.7.5": "‘Thưa Đại vương, trên đường đi ra vườn ngự uyển, Hoàng tử đã trông thấy một người bệnh, khổ sở, ốm nặng, nằm lăn trong phân và nước tiểu của chính mình, được người khác nâng dậy, được người khác đặt nằm xuống. ",
  "dn14:2.7.6": "Thấy vậy, Hoàng tử đã nói với tôi: ",
  "dn14:2.7.7": "“Này bạn đánh xe, người ấy đã làm gì, đôi mắt của người ấy không giống như của người khác, giọng nói của người ấy không giống như của người khác?” ",
  "dn14:2.7.8": "“Thưa Điện hạ, đó gọi là người bệnh.” ",
  "dn14:2.7.9": "“Này bạn đánh xe, vì sao gọi là người bệnh?” ",
  "dn14:2.7.10": "“Thưa Điện hạ, đó gọi là người bệnh, may ra người ấy có thể thoát khỏi bệnh ấy.” ",
  "dn14:2.7.11": "“Này bạn đánh xe, vậy ta cũng chịu pháp bệnh, không vượt khỏi bệnh chăng?” ",
  "dn14:2.7.12": "“Thưa Điện hạ, cả ngài và chúng tôi đều chịu pháp bệnh, không vượt khỏi bệnh.” ",
  "dn14:2.7.13": "“Vậy thì, này bạn đánh xe, hôm nay thôi vườn ngự uyển, hãy cho xe quay về cung ngay từ đây.” ",
  "dn14:2.7.14": "“Thưa vâng, Điện hạ”, thưa Đại vương, tôi vâng lời Hoàng tử Vipassī, cho xe quay về cung ngay từ đó. ",
  "dn14:2.7.15": "Thưa Đại vương, Hoàng tử trở về cung, khổ sầu, buồn bã, suy tư: ",
  "dn14:2.7.16": "“Thật đáng chê trách cho sự sinh này, khi có sinh ra thì có già, có bệnh.”’ ",
  "dn14:2.8.0": "7. Người chết ",
  "dn14:2.8.1": "Rồi này các Tỳ Kheo, vua Bandhuma khởi lên ý nghĩ: ",
  "dn14:2.8.2": "‘Chớ để Hoàng tử Vipassī không trị vì, chớ để Hoàng tử Vipassī xuất gia từ bỏ đời sống gia đình sống đời không nhà, chớ để lời nói của các Bà-la-môn tinh thông tướng số thành sự thật.’ ",
  "dn14:2.8.3": "Rồi này các Tỳ Kheo, vua Bandhuma cung cấp cho Hoàng tử Vipassī năm dục trưởng dưỡng càng nhiều hơn: ",
  "dn14:2.8.4": "‘Để Hoàng tử Vipassī trị vì, để Hoàng tử Vipassī không xuất gia từ bỏ đời sống gia đình sống đời không nhà, để lời nói của các Bà-la-môn tinh thông tướng số thành sai.’ ",
  "dn14:2.9.1": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī với năm dục trưởng dưỡng được cung cấp đầy đủ, thỏa mãn, tận hưởng. ",
  "dn14:2.9.2": "Rồi này các Tỳ Kheo, sau nhiều năm, Hoàng tử Vipassī …(v.v.)… ",
  "dn14:2.10.1": "Này các Tỳ Kheo, Hoàng tử Vipassī trên đường đi ra vườn ngự uyển, trông thấy một đám đông người tụ họp lại và đang làm một loại vải màu sắc khác nhau. ",
  "dn14:2.10.2": "Thấy vậy, ngài hỏi người đánh xe: ",
  "dn14:2.10.3": "‘Này bạn đánh xe, vì sao đám đông người ấy tụ họp lại và đang làm một loại vải màu sắc khác nhau?’ ",
  "dn14:2.10.4": "‘Thưa Điện hạ, đó gọi là người chết.’ ",
  "dn14:2.10.5": "‘Vậy thì, này bạn đánh xe, hãy cho xe đến chỗ người chết ấy.’ ",
  "dn14:2.10.6": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, cho xe đến chỗ người chết ấy. ",
  "dn14:2.10.7": "Này các Tỳ Kheo, Hoàng tử Vipassī trông thấy tử thi của người chết, thấy rồi ngài hỏi người đánh xe: ",
  "dn14:2.10.8": "‘Này bạn đánh xe, người chết ấy là gì?’ ",
  "dn14:2.10.9": "‘Thưa Điện hạ, đó gọi là người chết. Từ nay cha mẹ hay bà con thân quyến không còn thấy người ấy nữa, và người ấy cũng không còn thấy cha mẹ hay bà con thân quyến.’ ",
  "dn14:2.10.10": "‘Này bạn đánh xe, vậy ta cũng chịu pháp chết, không vượt khỏi chết chăng? ",
  "dn14:2.10.11": "Cả phụ vương, mẫu hậu hay bà con thân quyến cũng không còn thấy ta nữa; ",
  "dn14:2.10.12": "và ta cũng không còn thấy phụ vương, mẫu hậu hay bà con thân quyến chăng?’ ",
  "dn14:2.10.13": "‘Thưa Điện hạ, cả ngài và chúng tôi đều chịu pháp chết, không vượt khỏi chết; ",
  "dn14:2.10.14": "cả phụ vương, mẫu hậu hay bà con thân quyến cũng không còn thấy ngài nữa; ",
  "dn14:2.10.15": "và ngài cũng không còn thấy phụ vương, mẫu hậu hay bà con thân quyến.’ ",
  "dn14:2.10.16": "‘Vậy thì, này bạn đánh xe, hôm nay thôi vườn ngự uyển, hãy cho xe quay về cung ngay từ đây.’ ",
  "dn14:2.10.17": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, cho xe quay về cung ngay từ đó. ",
  "dn14:2.10.18": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī trở về cung, khổ sầu, buồn bã, suy tư: ",
  "dn14:2.10.19": "‘Thật đáng chê trách cho sự sinh này, khi có sinh ra thì có già, có bệnh, có chết.’ ",
  "dn14:2.11.1": "Rồi này các Tỳ Kheo, vua Bandhuma cho gọi người đánh xe đến và hỏi: ",
  "dn14:2.11.2": "‘Này bạn đánh xe, Hoàng tử có vui vẻ ở vườn ngự uyển không, này bạn đánh xe, Hoàng tử có hoan hỷ ở vườn ngự uyển không?’ ",
  "dn14:2.11.3": "‘Thưa Đại vương, Hoàng tử không vui vẻ ở vườn ngự uyển, thưa Đại vương, Hoàng tử không hoan hỷ ở vườn ngự uyển.’ ",
  "dn14:2.11.4": "‘Này bạn đánh xe, trên đường đi ra vườn ngự uyển, Hoàng tử đã trông thấy gì?’ ",
  "dn14:2.11.5": "‘Thưa Đại vương, trên đường đi ra vườn ngự uyển, Hoàng tử đã trông thấy một đám đông người tụ họp lại và đang làm một loại vải màu sắc khác nhau. ",
  "dn14:2.11.6": "Thấy vậy, Hoàng tử đã nói với tôi: ",
  "dn14:2.11.7": "“Này bạn đánh xe, vì sao đám đông người ấy tụ họp lại và đang làm một loại vải màu sắc khác nhau?” ",
  "dn14:2.11.8": "“Thưa Điện hạ, đó gọi là người chết.” ",
  "dn14:2.11.9": "“Vậy thì, này bạn đánh xe, hãy cho xe đến chỗ người chết ấy.” ",
  "dn14:2.11.10": "“Thưa vâng, Điện hạ”, thưa Đại vương, tôi vâng lời Hoàng tử Vipassī, cho xe đến chỗ người chết ấy. ",
  "dn14:2.11.11": "Thưa Đại vương, Hoàng tử trông thấy tử thi của người chết, thấy rồi ngài đã nói với tôi: ",
  "dn14:2.11.12": "“Này bạn đánh xe, người chết ấy là gì?” ",
  "dn14:2.11.13": "“Thưa Điện hạ, đó gọi là người chết. ",
  "dn14:2.11.14": "Từ nay cha mẹ hay bà con thân quyến không còn thấy người ấy nữa, và người ấy cũng không còn thấy cha mẹ hay bà con thân quyến.” ",
  "dn14:2.11.15": "“Này bạn đánh xe, vậy ta cũng chịu pháp chết, không vượt khỏi chết chăng; ",
  "dn14:2.11.16": "cả phụ vương, mẫu hậu hay bà con thân quyến cũng không còn thấy ta nữa; ",
  "dn14:2.11.17": "và ta cũng không còn thấy phụ vương, mẫu hậu hay bà con thân quyến chăng?” ",
  "dn14:2.11.18": "“Thưa Điện hạ, cả ngài và chúng tôi đều chịu pháp chết, không vượt khỏi chết; ",
  "dn14:2.11.19": "cả phụ vương, mẫu hậu hay bà con thân quyến cũng không còn thấy ngài nữa, và ngài cũng không còn thấy phụ vương, mẫu hậu hay bà con thân quyến.” ",
  "dn14:2.11.20": "“Vậy thì, này bạn đánh xe, hôm nay thôi vườn ngự uyển, hãy cho xe quay về cung ngay từ đây.” ",
  "dn14:2.11.21": "“Thưa vâng, Điện hạ”, thưa Đại vương, tôi vâng lời Hoàng tử Vipassī, cho xe quay về cung ngay từ đó. ",
  "dn14:2.11.22": "Thưa Đại vương, Hoàng tử trở về cung, khổ sầu, buồn bã, suy tư: ",
  "dn14:2.11.23": "“Thật đáng chê trách cho sự sinh này, khi có sinh ra thì có già, có bệnh, có chết.”’ ",
  "dn14:2.12.0": "8. Người xuất gia ",
  "dn14:2.12.1": "Rồi này các Tỳ Kheo, vua Bandhuma khởi lên ý nghĩ: ",
  "dn14:2.12.2": "‘Chớ để Hoàng tử Vipassī không trị vì, chớ để Hoàng tử Vipassī xuất gia từ bỏ đời sống gia đình sống đời không nhà, chớ để lời nói của các Bà-la-môn tinh thông tướng số thành sự thật.’ ",
  "dn14:2.12.3": "Rồi này các Tỳ Kheo, vua Bandhuma cung cấp cho Hoàng tử Vipassī năm dục trưởng dưỡng càng nhiều hơn: ",
  "dn14:2.12.4": "‘Để Hoàng tử Vipassī trị vì, để Hoàng tử Vipassī không xuất gia từ bỏ đời sống gia đình sống đời không nhà, để lời nói của các Bà-la-môn tinh thông tướng số thành sai.’ ",
  "dn14:2.13.1": "Tại đó, này các Tỳ Kheo, Hoàng tử Vipassī với năm dục trưởng dưỡng được cung cấp đầy đủ, thỏa mãn, tận hưởng. ",
  "dn14:2.13.2": "Rồi này các Tỳ Kheo, sau nhiều năm, nhiều trăm năm, nhiều ngàn năm, Hoàng tử Vipassī gọi người đánh xe: ",
  "dn14:2.13.3": "‘Này bạn đánh xe, hãy thắng những cỗ xe tốt, ta đi ra vườn ngự uyển để ngắm cảnh đẹp.’ ",
  "dn14:2.13.4": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, thắng những cỗ xe tốt rồi báo cho Hoàng tử Vipassī: ",
  "dn14:2.13.5": "‘Thưa Điện hạ, các cỗ xe tốt đã thắng xong, ",
  "dn14:2.13.6": "xin Điện hạ định giờ nào.’ ",
  "dn14:2.13.7": "Rồi này các Tỳ Kheo, Hoàng tử Vipassī leo lên cỗ xe tốt, cùng với các cỗ xe tốt đi ra vườn ngự uyển. ",
  "dn14:2.14.1": "Này các Tỳ Kheo, Hoàng tử Vipassī trên đường đi ra vườn ngự uyển, trông thấy một người cạo đầu, xuất gia, mặc y áo cà-sa. ",
  "dn14:2.14.2": "Thấy vậy, ngài hỏi người đánh xe: ",
  "dn14:2.14.3": "‘Này bạn đánh xe, người ấy đã làm gì? ",
  "dn14:2.14.4": "Đầu của người ấy không giống như của người khác, y áo của người ấy không giống như của người khác.’ ",
  "dn14:2.14.5": "‘Thưa Điện hạ, đó gọi là người xuất gia.’ ",
  "dn14:2.14.6": "‘Này bạn đánh xe, vì sao gọi là người xuất gia?’ ",
  "dn14:2.14.7": "‘Thưa Điện hạ, đó gọi là người xuất gia: lành thay sự hành pháp, lành thay sự hành bình đẳng, lành thay sự làm việc thiện, lành thay sự làm việc phước, lành thay sự không hại, lành thay lòng thương xót chúng sinh.’ ",
  "dn14:2.14.8": "‘Lành thay người xuất gia ấy, này bạn đánh xe, lành thay sự hành pháp, lành thay sự hành bình đẳng, lành thay sự làm việc thiện, lành thay sự làm việc phước, lành thay sự không hại, lành thay lòng thương xót chúng sinh. ",
  "dn14:2.14.9": "Vậy thì, này bạn đánh xe, hãy cho xe đến chỗ người xuất gia ấy.’ ",
  "dn14:2.14.10": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, cho xe đến chỗ người xuất gia ấy. ",
  "dn14:2.14.11": "Rồi này các Tỳ Kheo, Hoàng tử Vipassī nói với người xuất gia ấy: ",
  "dn14:2.14.12": "‘Này bạn, ông đã làm gì, ",
  "dn14:2.14.13": "đầu của ông không giống như của người khác, y áo của ông không giống như của người khác?’ ",
  "dn14:2.14.14": "‘Thưa Điện hạ, tôi là người xuất gia.’ ",
  "dn14:2.14.15": "‘Này bạn, thế nào là người xuất gia?’ ",
  "dn14:2.14.16": "‘Thưa Điện hạ, tôi là người xuất gia, lành thay sự hành pháp, lành thay sự hành bình đẳng, lành thay sự làm việc thiện, lành thay sự làm việc phước, lành thay sự không hại, lành thay lòng thương xót chúng sinh.’ ",
  "dn14:2.14.17": "‘Lành thay ông, này bạn, là người xuất gia, lành thay sự hành pháp, lành thay sự hành bình đẳng, lành thay sự làm việc thiện, lành thay sự làm việc phước, lành thay sự không hại, lành thay lòng thương xót chúng sinh.’ ",
  "dn14:2.15.0": "9. Bồ-tát xuất gia ",
  "dn14:2.15.1": "Rồi này các Tỳ Kheo, Hoàng tử Vipassī gọi người đánh xe: ",
  "dn14:2.15.2": "‘Vậy thì, này bạn đánh xe, hãy đem xe về cung ngay từ đây. ",
  "dn14:2.15.3": "Còn ta thì ngay tại đây, sẽ cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà.’ ",
  "dn14:2.15.4": "‘Thưa vâng, Điện hạ’, này các Tỳ Kheo, người đánh xe vâng lời Hoàng tử Vipassī, đem xe về cung ngay từ đó. ",
  "dn14:2.15.5": "Còn Hoàng tử Vipassī thì ngay tại đó, cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà. ",
  "dn14:2.16.0": "10. Đại chúng cùng xuất gia ",
  "dn14:2.16.1": "Này các Tỳ Kheo, đại chúng gồm tám mươi bốn ngàn người ở kinh đô Bandhumatī nghe tin: ",
  "dn14:2.16.2": "‘Nghe nói Hoàng tử Vipassī đã cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà.’ ",
  "dn14:2.16.3": "Nghe vậy, họ khởi lên ý nghĩ: ",
  "dn14:2.16.4": "‘Chắc chắn pháp và luật ấy không phải là tầm thường, sự xuất gia ấy không phải là tầm thường, khi Hoàng tử Vipassī đã cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà. ",
  "dn14:2.16.5": "Ngay cả Hoàng tử Vipassī mà còn cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà, huống gì chúng ta?’ ",
  "dn14:2.16.6": "Rồi này các Tỳ Kheo, đại chúng gồm tám mươi bốn ngàn người ấy cạo bỏ râu tóc, mặc y áo cà-sa, và cùng xuất gia từ bỏ đời sống gia đình sống đời không nhà theo Bồ-tát Vipassī. ",
  "dn14:2.16.7": "Được đoàn thể ấy vây quanh, này các Tỳ Kheo, Bồ-tát Vipassī du hành qua các làng mạc, thị trấn, các vùng đất, các kinh đô. ",
  "dn14:2.17.1": "Rồi này các Tỳ Kheo, khi Bồ-tát Vipassī ở một mình nơi yên tĩnh, trong tâm khởi lên ý nghĩ như sau: ",
  "dn14:2.17.2": "‘Sống giữa đám đông không thích hợp với ta, vậy ta nên sống một mình xa lánh đám đông.’ ",
  "dn14:2.17.3": "Rồi này các Tỳ Kheo, một thời gian sau, Bồ-tát Vipassī sống một mình xa lánh đám đông; tám mươi bốn ngàn người xuất gia ấy đi một đường khác, còn Bồ-tát Vipassī đi một đường khác. ",
  "dn14:2.18.0": "11. Sự quán chiếu của Bồ-tát ",
  "dn14:2.18.1": "Rồi này các Tỳ Kheo, khi Bồ-tát Vipassī đến một chỗ trú ngụ, ở một mình nơi yên tĩnh, trong tâm khởi lên ý nghĩ như sau: ",
  "dn14:2.18.2": "‘Thế gian này thật khổ sở, có sinh, có già, có chết, có tử, có tái sinh, mà lại không biết con đường thoát khỏi khổ này, thoát khỏi già chết, ",
  "dn14:2.18.3": "bao giờ mới tìm ra con đường thoát khỏi khổ này, thoát khỏi già chết?’ ",
  "dn14:2.18.4": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.5": "‘Do cái gì có mà có già chết, do duyên gì có già chết?’ ",
  "dn14:2.18.6": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.7": "‘Do có sinh mà có già chết, do duyên sinh mà có già chết.’ ",
  "dn14:2.18.8": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.9": "‘Do cái gì có mà có sinh, do duyên gì có sinh?’ ",
  "dn14:2.18.10": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.11": "‘Do có hữu mà có sinh, do duyên hữu mà có sinh.’ ",
  "dn14:2.18.12": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.13": "‘Do cái gì có mà có hữu, do duyên gì có hữu?’ ",
  "dn14:2.18.14": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.15": "‘Do có thủ mà có hữu, do duyên thủ mà có hữu.’ ",
  "dn14:2.18.16": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.17": "‘Do cái gì có mà có thủ, do duyên gì có thủ?’ ",
  "dn14:2.18.18": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.19": "‘Do có ái mà có thủ, do duyên ái mà có thủ.’ ",
  "dn14:2.18.20": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.21": "‘Do cái gì có mà có ái, do duyên gì có ái?’ ",
  "dn14:2.18.22": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.23": "‘Do có thọ mà có ái, do duyên thọ mà có ái.’ ",
  "dn14:2.18.24": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.25": "‘Do cái gì có mà có thọ, do duyên gì có thọ?’ ",
  "dn14:2.18.26": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.27": "‘Do có xúc mà có thọ, do duyên xúc mà có thọ.’ ",
  "dn14:2.18.28": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.29": "‘Do cái gì có mà có xúc, do duyên gì có xúc?’ ",
  "dn14:2.18.30": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.31": "‘Do có sáu nhập mà có xúc, do duyên sáu nhập mà có xúc.’ ",
  "dn14:2.18.32": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.33": "‘Do cái gì có mà có sáu nhập, do duyên gì có sáu nhập?’ ",
  "dn14:2.18.34": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.35": "‘Do có danh sắc mà có sáu nhập, do duyên danh sắc mà có sáu nhập.’ ",
  "dn14:2.18.36": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.37": "‘Do cái gì có mà có danh sắc, do duyên gì có danh sắc?’ ",
  "dn14:2.18.38": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.39": "‘Do có thức mà có danh sắc, do duyên thức mà có danh sắc.’ ",
  "dn14:2.18.40": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.18.41": "‘Do cái gì có mà có thức, do duyên gì có thức?’ ",
  "dn14:2.18.42": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.18.43": "‘Do có danh sắc mà có thức, do duyên danh sắc mà có thức.’ ",
  "dn14:2.19.1": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.19.2": "‘Thức này quay trở về từ danh sắc, không đi xa hơn. ",
  "dn14:2.19.3": "Đến mức này thì có thể sinh, có thể già, có thể chết, có thể tử, có thể tái sinh, nghĩa là ",
  "dn14:2.19.4": "do duyên danh sắc mà có thức, do duyên thức mà có danh sắc, do duyên danh sắc mà có sáu nhập, do duyên sáu nhập mà có xúc, do duyên xúc mà có thọ, do duyên thọ mà có ái, do duyên ái mà có thủ, do duyên thủ mà có hữu, do duyên hữu mà có sinh, do duyên sinh mà có già chết, sầu, bi, khổ, ưu, não khởi lên. ",
  "dn14:2.19.5": "Như vậy là sự tập khởi của toàn bộ khổ uẩn này.’ ",
  "dn14:2.19.6": "Này các Tỳ Kheo, ‘tập khởi, tập khởi’, đối với Bồ-tát Vipassī về những pháp chưa từng được nghe trước đây, mắt khởi lên, trí khởi lên, tuệ khởi lên, minh khởi lên, ánh sáng khởi lên. ",
  "dn14:2.20.1": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.2": "‘Do cái gì không có mà không có già chết, do cái gì diệt mà già chết diệt?’ ",
  "dn14:2.20.3": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.4": "‘Do sinh không có mà già chết không có, do sinh diệt mà già chết diệt.’ ",
  "dn14:2.20.5": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.6": "‘Do cái gì không có mà không có sinh, do cái gì diệt mà sinh diệt?’ ",
  "dn14:2.20.7": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.8": "‘Do hữu không có mà sinh không có, do hữu diệt mà sinh diệt.’ ",
  "dn14:2.20.9": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.10": "‘Do cái gì không có mà không có hữu, do cái gì diệt mà hữu diệt?’ ",
  "dn14:2.20.11": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.12": "‘Do thủ không có mà hữu không có, do thủ diệt mà hữu diệt.’ ",
  "dn14:2.20.13": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.14": "‘Do cái gì không có mà không có thủ, do cái gì diệt mà thủ diệt?’ ",
  "dn14:2.20.15": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.16": "‘Do ái không có mà thủ không có, do ái diệt mà thủ diệt.’ ",
  "dn14:2.20.17": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.18": "‘Do cái gì không có mà không có ái, do cái gì diệt mà ái diệt?’ ",
  "dn14:2.20.19": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.20": "‘Do thọ không có mà ái không có, do thọ diệt mà ái diệt.’ ",
  "dn14:2.20.21": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.22": "‘Do cái gì không có mà không có thọ, do cái gì diệt mà thọ diệt?’ ",
  "dn14:2.20.23": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.24": "‘Do xúc không có mà thọ không có, do xúc diệt mà thọ diệt.’ ",
  "dn14:2.20.25": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.26": "‘Do cái gì không có mà không có xúc, do cái gì diệt mà xúc diệt?’ ",
  "dn14:2.20.27": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.28": "‘Do sáu nhập không có mà xúc không có, do sáu nhập diệt mà xúc diệt.’ ",
  "dn14:2.20.29": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.30": "‘Do cái gì không có mà không có sáu nhập, do cái gì diệt mà sáu nhập diệt?’ ",
  "dn14:2.20.31": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.32": "‘Do danh sắc không có mà sáu nhập không có, do danh sắc diệt mà sáu nhập diệt.’ ",
  "dn14:2.20.33": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.34": "‘Do cái gì không có mà không có danh sắc, do cái gì diệt mà danh sắc diệt?’ ",
  "dn14:2.20.35": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.36": "‘Do thức không có mà danh sắc không có, do thức diệt mà danh sắc diệt.’ ",
  "dn14:2.20.37": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.20.38": "‘Do cái gì không có mà không có thức, do cái gì diệt mà thức diệt?’ ",
  "dn14:2.20.39": "Rồi này các Tỳ Kheo, do khéo tác ý, Bồ-tát Vipassī với trí tuệ khởi lên sự liễu tri: ",
  "dn14:2.20.40": "‘Do danh sắc không có mà thức không có, do danh sắc diệt mà thức diệt.’ ",
  "dn14:2.21.1": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī khởi lên ý nghĩ này: ",
  "dn14:2.21.2": "‘Ta đã chứng đắc con đường đưa đến giác ngộ, đó là—",
  "dn14:2.21.3": "do danh sắc diệt mà thức diệt, do thức diệt mà danh sắc diệt, do danh sắc diệt mà sáu nhập diệt, do sáu nhập diệt mà xúc diệt, do xúc diệt mà thọ diệt, do thọ diệt mà ái diệt, do ái diệt mà thủ diệt, do thủ diệt mà hữu diệt, do hữu diệt mà sinh diệt, do sinh diệt mà già chết, sầu, bi, khổ, ưu, não diệt. ",
  "dn14:2.21.4": "Như vậy là sự đoạn diệt của toàn bộ khổ uẩn này.’ ",
  "dn14:2.21.5": "Này các Tỳ Kheo, ‘đoạn diệt, đoạn diệt’, đối với Bồ-tát Vipassī về những pháp chưa từng được nghe trước đây, mắt khởi lên, trí khởi lên, tuệ khởi lên, minh khởi lên, ánh sáng khởi lên. ",
  "dn14:2.22.1": "Rồi này các Tỳ Kheo, Bồ-tát Vipassī một thời gian sau sống quán sát sự sinh diệt của năm thủ uẩn: ",
  "dn14:2.22.2": "‘Đây là sắc, đây là sự sinh khởi của sắc, đây là sự đoạn diệt của sắc; ",
  "dn14:2.22.3": "đây là thọ, đây là sự sinh khởi của thọ, đây là sự đoạn diệt của thọ; ",
  "dn14:2.22.4": "đây là tưởng, đây là sự sinh khởi của tưởng, đây là sự đoạn diệt của tưởng; ",
  "dn14:2.22.5": "đây là các hành, đây là sự sinh khởi của các hành, đây là sự đoạn diệt của các hành; ",
  "dn14:2.22.6": "đây là thức, đây là sự sinh khởi của thức, đây là sự đoạn diệt của thức.’ ",
  "dn14:2.22.7": "Khi vị ấy sống quán sát sự sinh diệt của năm thủ uẩn, không bao lâu tâm vị ấy được giải thoát, không còn chấp thủ, khỏi các lậu hoặc. ",
  "dn14:2.22.8": "Hết tụng phần thứ hai. ",
  "dn14:3.1.0": "12. Phạm thiên thỉnh cầu ",
  "dn14:3.1.1": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác khởi lên ý nghĩ này: ",
  "dn14:3.1.2": "‘Vậy ta hãy thuyết pháp.’ ",
  "dn14:3.1.3": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác khởi lên ý nghĩ này: ",
  "dn14:3.1.4": "‘Pháp mà ta đã chứng đắc này thật sâu xa, khó thấy, khó hiểu, tịch tịnh, thù thắng, vượt khỏi suy luận, vi diệu, chỉ bậc trí mới cảm nhận được. ",
  "dn14:3.1.5": "Chúng sinh này thì chấp thủ, ưa thích chấp thủ, vui mừng trong chấp thủ. ",
  "dn14:3.1.6": "Đối với chúng sinh chấp thủ, ưa thích chấp thủ, vui mừng trong chấp thủ, thì điều này thật khó thấy, tức là tính duyên khởi, lý duyên sinh. ",
  "dn14:3.1.7": "Điều này cũng khó thấy, tức là sự vắng lặng của tất cả các hành, sự từ bỏ tất cả các chấp thủ, sự đoạn tận tham ái, ly tham, đoạn diệt, Niết-bàn. ",
  "dn14:3.1.8": "Nếu ta thuyết pháp mà người khác không hiểu được, thì thật nhọc sức cho ta, thật phiền toái cho ta.’ ",
  "dn14:3.2.1": "Này các Tỳ Kheo, rồi các bài kệ hiếm có sau đây, chưa từng được nghe trước đây, khởi lên trong tâm Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác: ",
  "dn14:3.2.2": "‘Pháp ta chứng đắc khó khăn, ",
  "dn14:3.2.3": "Há nên công bố bây giờ; ",
  "dn14:3.2.4": "Những kẻ bị tham sân xâm chiếm, ",
  "dn14:3.2.5": "Khó mà liễu ngộ pháp này. ",
  "dn14:3.2.6": "Đi ngược dòng, vi diệu, ",
  "dn14:3.2.7": "Sâu xa, khó thấy, vi tế; ",
  "dn14:3.2.8": "Kẻ đắm tham không thấy được, ",
  "dn14:3.2.9": "Vì bị khối tối che phủ.’ ",
  "dn14:3.2.10": "Này các Tỳ Kheo, khi Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác suy tư như vậy, tâm Ngài thiên về việc không nhiệt tâm, không thiên về việc thuyết pháp. ",
  "dn14:3.2.11": "Rồi này các Tỳ Kheo, có một vị Đại Phạm Thiên với tâm mình biết được suy nghĩ trong tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, khởi lên ý nghĩ: ",
  "dn14:3.2.12": "‘Quý vị ơi, thế gian đang bị hủy diệt, thế gian đang bị tiêu diệt, khi tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thiên về việc không nhiệt tâm, không thiên về việc thuyết pháp.’ ",
  "dn14:3.2.13": "Rồi này các Tỳ Kheo, vị Đại Phạm Thiên ấy—ví như một người lực sĩ co duỗi cánh tay, hay duỗi co cánh tay; cũng vậy—biến mất khỏi cõi Phạm thiên và xuất hiện trước mặt Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn14:3.3.1": "Rồi này các Tỳ Kheo, vị Đại Phạm Thiên ấy vắt y thượng lên một vai, đặt đầu gối phải xuống đất, chắp tay hướng về phía Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác và bạch Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rằng: ",
  "dn14:3.3.2": "‘Bạch Thế Tôn, xin Thế Tôn hãy thuyết pháp, xin Thiện Thệ hãy thuyết pháp, ",
  "dn14:3.3.3": "có những chúng sinh ít nhiễm cấu; nếu không nghe pháp họ sẽ bị hư hoại, ",
  "dn14:3.3.4": "sẽ có những người hiểu được pháp.’ ",
  "dn14:3.4.1": "Khi được nói vậy, này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác nói với vị Đại Phạm Thiên ấy: ",
  "dn14:3.4.2": "‘Này Phạm thiên, ta cũng đã khởi lên ý nghĩ: ",
  "dn14:3.4.3": "“Vậy ta hãy thuyết pháp.” ",
  "dn14:3.4.4": "Rồi này Phạm thiên, ta cũng đã khởi lên ý nghĩ: ",
  "dn14:3.4.5": "“Pháp mà ta đã chứng đắc này thật sâu xa, khó thấy, khó hiểu, tịch tịnh, thù thắng, vượt khỏi suy luận, vi diệu, chỉ bậc trí mới cảm nhận được. ",
  "dn14:3.4.6": "Chúng sinh này thì chấp thủ, ưa thích chấp thủ, vui mừng trong chấp thủ. ",
  "dn14:3.4.7": "Đối với chúng sinh chấp thủ, ưa thích chấp thủ, vui mừng trong chấp thủ, thì điều này thật khó thấy, tức là tính duyên khởi, lý duyên sinh. ",
  "dn14:3.4.8": "Điều này cũng khó thấy, tức là sự vắng lặng của tất cả các hành, sự từ bỏ tất cả các chấp thủ, sự đoạn tận tham ái, ly tham, đoạn diệt, Niết-bàn. ",
  "dn14:3.4.9": "Nếu ta thuyết pháp mà người khác không hiểu được, thì thật nhọc sức cho ta, thật phiền toái cho ta.” ",
  "dn14:3.4.10": "Này Phạm thiên, rồi các bài kệ hiếm có sau đây, chưa từng được nghe trước đây, khởi lên trong tâm ta: ",
  "dn14:3.4.11": "“Pháp ta chứng đắc khó khăn, ",
  "dn14:3.4.12": "Há nên công bố bây giờ; ",
  "dn14:3.4.13": "Những kẻ bị tham sân xâm chiếm, ",
  "dn14:3.4.14": "Khó mà liễu ngộ pháp này. ",
  "dn14:3.4.15": "Đi ngược dòng, vi diệu, ",
  "dn14:3.4.16": "Sâu xa, khó thấy, vi tế; ",
  "dn14:3.4.17": "Kẻ đắm tham không thấy được, ",
  "dn14:3.4.18": "Vì bị khối tối che phủ.” ",
  "dn14:3.4.19": "Này Phạm thiên, khi ta suy tư như vậy, tâm ta thiên về việc không nhiệt tâm, không thiên về việc thuyết pháp.’ ",
  "dn14:3.5.1": "Này các Tỳ Kheo, lần thứ hai vị Đại Phạm Thiên ấy …(v.v.)… ",
  "dn14:3.5.2": "lần thứ ba vị Đại Phạm Thiên ấy bạch Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác: ",
  "dn14:3.5.3": "‘Bạch Thế Tôn, xin Thế Tôn hãy thuyết pháp, xin Thiện Thệ hãy thuyết pháp, có những chúng sinh ít nhiễm cấu, nếu không nghe pháp họ sẽ bị hư hoại, sẽ có những người hiểu được pháp.’ ",
  "dn14:3.6.1": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác sau khi biết lời thỉnh cầu của Phạm thiên và do lòng thương tưởng đối với các chúng sinh, với Phật nhãn nhìn khắp thế gian. ",
  "dn14:3.6.2": "Này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác với Phật nhãn nhìn khắp thế gian, thấy các chúng sinh ít nhiễm cấu, nhiều nhiễm cấu, căn tánh nhạy bén, căn tánh cùn, có đặc tính tốt, có đặc tính xấu, dễ dạy, khó dạy, một số sống thấy sợ hãi tội lỗi và đời sau, một số sống không thấy sợ hãi tội lỗi và đời sau. ",
  "dn14:3.6.3": "Ví như trong hồ sen xanh, sen đỏ hay sen trắng, có một số hoa sen xanh, hoa sen đỏ hay hoa sen trắng mọc trong nước, lớn lên trong nước, không vươn lên khỏi mặt nước, được nuôi dưỡng dưới nước; có một số hoa sen xanh, hoa sen đỏ hay hoa sen trắng mọc trong nước, lớn lên trong nước, vươn lên bằng mặt nước; có một số hoa sen xanh, hoa sen đỏ hay hoa sen trắng mọc trong nước, lớn lên trong nước, vươn lên khỏi mặt nước, không bị nước thấm. ",
  "dn14:3.6.4": "Cũng vậy, này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác với Phật nhãn nhìn khắp thế gian, thấy các chúng sinh ít nhiễm cấu, nhiều nhiễm cấu, căn tánh nhạy bén, căn tánh cùn, có đặc tính tốt, có đặc tính xấu, dễ dạy, khó dạy, một số sống thấy sợ hãi tội lỗi và đời sau, một số sống không thấy sợ hãi tội lỗi và đời sau. ",
  "dn14:3.7.1": "Rồi này các Tỳ Kheo, vị Đại Phạm Thiên ấy biết được suy nghĩ trong tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đã nói với Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác bằng những bài kệ: ",
  "dn14:3.7.2": "‘Như người đứng trên đỉnh núi đá, ",
  "dn14:3.7.3": "Nhìn thấy dân chúng khắp chung quanh; ",
  "dn14:3.7.4": "Cũng vậy, bậc thiện trí, có toàn nhãn, ",
  "dn14:3.7.5": "Bước lên tòa pháp quán sát khắp; ",
  "dn14:3.7.6": "Bậc đã thoát sầu, hãy quán sát, ",
  "dn14:3.7.7": "Quần chúng đang bị sầu hãm, bị già chết chi phối. ",
  "dn14:3.7.8": "Hãy đứng dậy, hỡi bậc anh hùng đã chiến thắng, ",
  "dn14:3.7.9": "Hỡi bậc dẫn đoàn, không nợ, du hành khắp đời; ",
  "dn14:3.7.10": "Xin Thế Tôn hãy thuyết pháp, ",
  "dn14:3.7.11": "Sẽ có những người hiểu được.’ ",
  "dn14:3.7.12": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác nói với vị Đại Phạm Thiên ấy bằng bài kệ: ",
  "dn14:3.7.13": "‘Cửa bất tử đã rộng mở cho chúng, ",
  "dn14:3.7.14": "Những ai có tai, hãy phát sinh lòng tin; ",
  "dn14:3.7.15": "Này Phạm thiên, với ý nghĩ phiền toái, ta đã không giảng, ",
  "dn14:3.7.16": "Pháp cao quý vi diệu cho loài người.’ ",
  "dn14:3.7.17": "Rồi này các Tỳ Kheo, vị Đại Phạm Thiên ấy nghĩ: ‘Ta đã được Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chấp thuận cho việc thuyết pháp’, đảnh lễ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đi nhiễu bên phải rồi biến mất ngay tại đó. ",
  "dn14:3.8.0": "13. Hai vị đệ tử tối thượng ",
  "dn14:3.8.1": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác khởi lên ý nghĩ này: ",
  "dn14:3.8.2": "‘Ta nên thuyết pháp trước tiên cho ai, ",
  "dn14:3.8.3": "ai sẽ hiểu nhanh pháp này?’ ",
  "dn14:3.8.4": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác khởi lên ý nghĩ này: ",
  "dn14:3.8.5": "‘Có Hoàng tử Khaṇḍa và con trai vị tế sư Bà-la-môn Tissa đang sống ở kinh đô Bandhumatī, đều là bậc thông thái, thiện xảo, có trí tuệ, từ lâu ít nhiễm cấu. ",
  "dn14:3.8.6": "Vậy ta nên thuyết pháp trước tiên cho Hoàng tử Khaṇḍa và con trai vị tế sư Bà-la-môn Tissa, họ sẽ hiểu nhanh pháp này.’ ",
  "dn14:3.9.1": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác—ví như một người lực sĩ co duỗi cánh tay, hay duỗi co cánh tay; cũng vậy—biến mất dưới cây bồ-đề và xuất hiện tại vườn nai Khema ở kinh đô Bandhumatī. ",
  "dn14:3.9.2": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác gọi người giữ vườn: ",
  "dn14:3.9.3": "‘Này bạn người giữ vườn, hãy đi vào kinh đô Bandhumatī và nói với Hoàng tử Khaṇḍa và con trai vị tế sư Tissa như sau—",
  "dn14:3.9.4": "thưa quý ngài, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã đến kinh đô Bandhumatī, đang trú tại vườn nai Khema, ngài muốn gặp quý vị.’ ",
  "dn14:3.9.5": "‘Thưa vâng, Tôn giả’, này các Tỳ Kheo, người giữ vườn vâng lời Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đi vào kinh đô Bandhumatī và nói với Hoàng tử Khaṇḍa và con trai vị tế sư Tissa rằng: ",
  "dn14:3.9.6": "‘Thưa quý ngài, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã đến kinh đô Bandhumatī, đang trú tại vườn nai Khema; ngài muốn gặp quý vị.’ ",
  "dn14:3.10.1": "Rồi này các Tỳ Kheo, Hoàng tử Khaṇḍa và con trai vị tế sư Tissa cho thắng những cỗ xe tốt, lên cỗ xe tốt, cùng với các cỗ xe tốt đi ra khỏi kinh đô Bandhumatī. Các vị ấy đi về phía vườn nai Khema. ",
  "dn14:3.10.2": "Đi đến nơi mà xe có thể đi được, họ xuống xe và đi bộ đến chỗ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác; sau khi đến, họ đảnh lễ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rồi ngồi xuống một bên. ",
  "dn14:3.11.1": "Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác tuần tự thuyết pháp cho họ, tức là—",
  "dn14:3.11.2": "thuyết về bố thí, thuyết về giới, thuyết về thiên giới; giảng về sự nguy hiểm, thấp hèn, nhiễm ô của các dục, lợi ích của sự xuất ly. ",
  "dn14:3.11.3": "Khi Thế Tôn biết tâm họ đã sẵn sàng, nhu nhuyến, không còn chướng ngại, hân hoan, tin tưởng, Ngài mới thuyết lên pháp thoại đặc thù của chư Phật—",
  "dn14:3.11.4": "Khổ, Tập, Diệt, Đạo. ",
  "dn14:3.11.5": "Ví như tấm vải trắng sạch, không có vết bẩn, có thể nhuộm màu hoàn hảo; ",
  "dn14:3.11.6": "cũng vậy, chính ngay tại chỗ ngồi ấy, pháp nhãn thanh tịnh, không nhiễm bụi khởi lên trong Hoàng tử Khaṇḍa và con trai vị tế sư Tissa: ",
  "dn14:3.11.7": "‘Bất cứ pháp gì có sự sinh khởi, tất cả đều có sự đoạn diệt.’ ",
  "dn14:3.12.1": "Họ đã thấy pháp, đạt đến pháp, hiểu rõ pháp, thâm nhập vào pháp, vượt qua nghi ngờ, đoạn tận do dự, đạt được sự tự tin, không còn nương tựa vào người khác trong giáo pháp của Đạo sư, thưa với Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác: ",
  "dn14:3.12.2": "‘Thật tuyệt vời thay, Bạch Thế Tôn, thật tuyệt vời thay, Bạch Thế Tôn. ",
  "dn14:3.12.3": "Ví như, Bạch Thế Tôn, có người dựng lại vật bị ngã, hay mở ra vật bị che kín, hay chỉ đường cho kẻ lạc lối, hay cầm đèn trong đêm tối để “người có mắt thấy được các hình sắc”; cũng vậy, Thế Tôn đã dùng nhiều phương tiện trình bày Pháp. ",
  "dn14:3.12.4": "Bạch Thế Tôn, chúng con xin quy y Thế Tôn và Pháp. ",
  "dn14:3.12.5": "Bạch Thế Tôn, chúng con xin được xuất gia dưới sự chỉ dạy của Thế Tôn, xin được thọ đại giới.’ ",
  "dn14:3.13.1": "Này các Tỳ Kheo, Hoàng tử Khaṇḍa và con trai vị tế sư Tissa được xuất gia và thọ đại giới dưới sự chỉ dạy của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn14:3.13.2": "Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chỉ dạy, khích lệ, làm cho họ phấn khởi, hoan hỷ bằng pháp thoại; ",
  "dn14:3.13.3": "Ngài giảng về sự nguy hiểm, thấp hèn, nhiễm ô của các hành và lợi ích của Niết-bàn. ",
  "dn14:3.13.4": "Khi được Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chỉ dạy, khích lệ, làm cho phấn khởi, hoan hỷ bằng pháp thoại, không bao lâu, tâm họ được giải thoát, không còn chấp thủ, khỏi các lậu hoặc. ",
  "dn14:3.14.0": "14. Đại chúng xuất gia ",
  "dn14:3.14.1": "Này các Tỳ Kheo, đại chúng gồm tám mươi bốn ngàn người ở kinh đô Bandhumatī nghe tin: ",
  "dn14:3.14.2": "‘Nghe nói Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã đến kinh đô Bandhumatī, đang trú tại vườn nai Khema. ",
  "dn14:3.14.3": "Và Hoàng tử Khaṇḍa cùng con trai vị tế sư Tissa đã cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà dưới sự chỉ dạy của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác.’ ",
  "dn14:3.14.4": "Nghe vậy, họ khởi lên ý nghĩ: ",
  "dn14:3.14.5": "‘Chắc chắn pháp và luật ấy không phải là tầm thường, sự xuất gia ấy không phải là tầm thường, khi Hoàng tử Khaṇḍa và con trai vị tế sư Tissa đã cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà. ",
  "dn14:3.14.6": "Ngay cả Hoàng tử Khaṇḍa và con trai vị tế sư Tissa còn cạo bỏ râu tóc, mặc y áo cà-sa, xuất gia từ bỏ đời sống gia đình sống đời không nhà, huống gì chúng ta?’ ",
  "dn14:3.14.7": "Rồi này các Tỳ Kheo, đại chúng gồm tám mươi bốn ngàn người ấy đi ra khỏi kinh đô Bandhumatī, đi đến vườn nai Khema, đến chỗ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác; sau khi đến, họ đảnh lễ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rồi ngồi xuống một bên. ",
  "dn14:3.15.1": "Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác tuần tự thuyết pháp cho họ. ",
  "dn14:3.15.2": "Tức là—thuyết về bố thí, thuyết về giới, thuyết về thiên giới; giảng về sự nguy hiểm, thấp hèn, nhiễm ô của các dục, lợi ích của sự xuất ly. ",
  "dn14:3.15.3": "Khi Thế Tôn biết tâm họ đã sẵn sàng, nhu nhuyến, không còn chướng ngại, hân hoan, tin tưởng, Ngài mới thuyết lên pháp thoại đặc thù của chư Phật—",
  "dn14:3.15.4": "Khổ, Tập, Diệt, Đạo. ",
  "dn14:3.15.5": "Ví như tấm vải trắng sạch, không có vết bẩn, có thể nhuộm màu hoàn hảo; ",
  "dn14:3.15.6": "cũng vậy, chính ngay tại chỗ ngồi ấy, pháp nhãn thanh tịnh, không nhiễm bụi khởi lên trong tám mươi bốn ngàn người ấy: ",
  "dn14:3.15.7": "‘Bất cứ pháp gì có sự sinh khởi, tất cả đều có sự đoạn diệt.’ ",
  "dn14:3.16.1": "Họ đã thấy pháp, đạt đến pháp, hiểu rõ pháp, thâm nhập vào pháp, vượt qua nghi ngờ, đoạn tận do dự, đạt được sự tự tin, không còn nương tựa vào người khác trong giáo pháp của Đạo sư, thưa với Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác: ",
  "dn14:3.16.2": "‘Thật tuyệt vời thay, Bạch Thế Tôn, thật tuyệt vời thay, Bạch Thế Tôn. ",
  "dn14:3.16.3": "Ví như, Bạch Thế Tôn, có người dựng lại vật bị ngã, hay mở ra vật bị che kín, hay chỉ đường cho kẻ lạc lối, hay cầm đèn trong đêm tối để “người có mắt thấy được các hình sắc”; cũng vậy, Thế Tôn đã dùng nhiều phương tiện trình bày Pháp. ",
  "dn14:3.16.4": "Bạch Thế Tôn, chúng con xin quy y Thế Tôn, quy y Pháp và chúng Tỳ Kheo. ",
  "dn14:3.16.5": "Bạch Thế Tôn, chúng con xin được xuất gia dưới sự chỉ dạy của Thế Tôn, xin được thọ đại giới.’ ",
  "dn14:3.17.1": "Này các Tỳ Kheo, tám mươi bốn ngàn người ấy được xuất gia và thọ đại giới dưới sự chỉ dạy của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn14:3.17.2": "Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chỉ dạy, khích lệ, làm cho họ phấn khởi, hoan hỷ bằng pháp thoại; ",
  "dn14:3.17.3": "Ngài giảng về sự nguy hiểm, thấp hèn, nhiễm ô của các hành và lợi ích của Niết-bàn. ",
  "dn14:3.17.4": "Khi được Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chỉ dạy, khích lệ, làm cho phấn khởi, hoan hỷ bằng pháp thoại, không bao lâu, tâm họ được giải thoát, không còn chấp thủ, khỏi các lậu hoặc. ",
  "dn14:3.18.0": "15. Sự chứng ngộ pháp của tám mươi bốn ngàn người xuất gia trước ",
  "dn14:3.18.1": "Này các Tỳ Kheo, tám mươi bốn ngàn người xuất gia trước đây nghe tin: ",
  "dn14:3.18.2": "‘Nghe nói Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã đến kinh đô Bandhumatī, đang trú tại vườn nai Khema, và đang thuyết pháp.’ ",
  "dn14:3.18.3": "Rồi này các Tỳ Kheo, tám mươi bốn ngàn người xuất gia ấy đi đến kinh đô Bandhumatī, đến vườn nai Khema, đến chỗ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác; sau khi đến, họ đảnh lễ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rồi ngồi xuống một bên. ",
  "dn14:3.19.1": "Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác tuần tự thuyết pháp cho họ. ",
  "dn14:3.19.2": "Tức là—thuyết về bố thí, thuyết về giới, thuyết về thiên giới; giảng về sự nguy hiểm, thấp hèn, nhiễm ô của các dục, lợi ích của sự xuất ly. ",
  "dn14:3.19.3": "Khi Thế Tôn biết tâm họ đã sẵn sàng, nhu nhuyến, không còn chướng ngại, hân hoan, tin tưởng, Ngài mới thuyết lên pháp thoại đặc thù của chư Phật—",
  "dn14:3.19.4": "Khổ, Tập, Diệt, Đạo. ",
  "dn14:3.19.5": "Ví như tấm vải trắng sạch, không có vết bẩn, có thể nhuộm màu hoàn hảo; ",
  "dn14:3.19.6": "cũng vậy, chính ngay tại chỗ ngồi ấy, pháp nhãn thanh tịnh, không nhiễm bụi khởi lên trong tám mươi bốn ngàn người xuất gia ấy: ",
  "dn14:3.19.7": "‘Bất cứ pháp gì có sự sinh khởi, tất cả đều có sự đoạn diệt.’ ",
  "dn14:3.20.1": "Họ đã thấy pháp, đạt đến pháp, hiểu rõ pháp, thâm nhập vào pháp, vượt qua nghi ngờ, đoạn tận do dự, đạt được sự tự tin, không còn nương tựa vào người khác trong giáo pháp của Đạo sư, thưa với Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác: ",
  "dn14:3.20.2": "‘Thật tuyệt vời thay, Bạch Thế Tôn, thật tuyệt vời thay, Bạch Thế Tôn. ",
  "dn14:3.20.3": "Ví như, Bạch Thế Tôn, có người dựng lại vật bị ngã, hay mở ra vật bị che kín, hay chỉ đường cho kẻ lạc lối, hay cầm đèn trong đêm tối để “người có mắt thấy được các hình sắc”; cũng vậy, Thế Tôn đã dùng nhiều phương tiện trình bày Pháp. ",
  "dn14:3.20.4": "Bạch Thế Tôn, chúng con xin quy y Thế Tôn, quy y Pháp và chúng Tỳ Kheo. ",
  "dn14:3.20.5": "Bạch Thế Tôn, chúng con xin được xuất gia dưới sự chỉ dạy của Thế Tôn, xin được thọ đại giới.’ ",
  "dn14:3.21.1": "Này các Tỳ Kheo, tám mươi bốn ngàn người xuất gia ấy được xuất gia và thọ đại giới dưới sự chỉ dạy của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn14:3.21.2": "Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chỉ dạy, khích lệ, làm cho họ phấn khởi, hoan hỷ bằng pháp thoại; ",
  "dn14:3.21.3": "Ngài giảng về sự nguy hiểm, thấp hèn, nhiễm ô của các hành và lợi ích của Niết-bàn. ",
  "dn14:3.21.4": "Khi được Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chỉ dạy, khích lệ, làm cho phấn khởi, hoan hỷ bằng pháp thoại, không bao lâu, tâm họ được giải thoát, không còn chấp thủ, khỏi các lậu hoặc. ",
  "dn14:3.22.0": "16. Cho phép du hành ",
  "dn14:3.22.1": "Lúc bấy giờ, này các Tỳ Kheo, đại chúng Tỳ Kheo gồm sáu triệu tám trăm ngàn vị đang cư trú tại kinh đô Bandhumatī. ",
  "dn14:3.22.2": "Rồi này các Tỳ Kheo, khi Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác ở một mình nơi yên tĩnh, trong tâm khởi lên ý nghĩ như sau: ",
  "dn14:3.22.3": "‘Hiện nay đại chúng Tỳ Kheo sáu triệu tám trăm ngàn vị đang cư trú tại kinh đô Bandhumatī, vậy ta nên cho phép các Tỳ Kheo: ",
  "dn14:3.22.4": "“Này các Tỳ Kheo, hãy đi du hành, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người; ",
  "dn14:3.22.5": "đừng hai người đi cùng một đường; ",
  "dn14:3.22.6": "này các Tỳ Kheo, hãy thuyết pháp sơ thiện, trung thiện, hậu thiện, đầy đủ ý nghĩa và văn cú, hãy trình bày đời sống phạm hạnh hoàn toàn viên mãn, thanh tịnh. ",
  "dn14:3.22.7": "Có những chúng sinh ít nhiễm cấu, nếu không nghe pháp họ sẽ bị hư hoại, ",
  "dn14:3.22.8": "sẽ có những người hiểu được pháp. ",
  "dn14:3.22.9": "Tuy nhiên, cứ mỗi sáu năm, phải đến kinh đô Bandhumatī để tụng đọc giới bổn.”’ ",
  "dn14:3.23.1": "Rồi này các Tỳ Kheo, có một vị Đại Phạm Thiên khác với tâm mình biết được suy nghĩ trong tâm của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, ví như một người lực sĩ co duỗi cánh tay, hay duỗi co cánh tay; cũng vậy—biến mất khỏi cõi Phạm thiên và xuất hiện trước mặt Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác. ",
  "dn14:3.23.2": "Rồi này các Tỳ Kheo, vị Đại Phạm Thiên ấy vắt y thượng lên một vai, chắp tay hướng về phía Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác và bạch Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác rằng: ",
  "dn14:3.23.3": "‘Đúng vậy, Bạch Thế Tôn, đúng vậy, Bạch Thiện Thệ. ",
  "dn14:3.23.4": "Bạch Thế Tôn, hiện nay đại chúng Tỳ Kheo sáu triệu tám trăm ngàn vị đang cư trú tại kinh đô Bandhumatī, xin Thế Tôn cho phép các Tỳ Kheo: ",
  "dn14:3.23.5": "“Này các Tỳ Kheo, hãy đi du hành, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người; ",
  "dn14:3.23.6": "đừng hai người đi cùng một đường; ",
  "dn14:3.23.7": "này các Tỳ Kheo, hãy thuyết pháp sơ thiện, trung thiện, hậu thiện, đầy đủ ý nghĩa và văn cú, hãy trình bày đời sống phạm hạnh hoàn toàn viên mãn, thanh tịnh. ",
  "dn14:3.23.8": "Có những chúng sinh ít nhiễm cấu, nếu không nghe pháp họ sẽ bị hư hoại, sẽ có những người hiểu được pháp.” ",
  "dn14:3.23.9": "Còn Bạch Thế Tôn, chúng con sẽ làm sao cho các Tỳ Kheo cứ mỗi sáu năm đều đến kinh đô Bandhumatī để tụng đọc giới bổn.’ ",
  "dn14:3.23.10": "Này các Tỳ Kheo, vị Đại Phạm Thiên ấy đã nói như vậy. ",
  "dn14:3.23.11": "Sau khi nói xong, đảnh lễ Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, đi nhiễu bên phải rồi biến mất ngay tại đó. ",
  "dn14:3.24.1": "Rồi này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, vào buổi chiều, xuất khỏi thiền tĩnh mịch, gọi các Tỳ Kheo: ",
  "dn14:3.24.2": "‘Này các Tỳ Kheo, khi ta ở một mình nơi yên tĩnh, trong tâm khởi lên ý nghĩ như sau: ",
  "dn14:3.24.3": "“Hiện nay đại chúng Tỳ Kheo sáu triệu tám trăm ngàn vị đang cư trú tại kinh đô Bandhumatī. ",
  "dn14:3.24.4": "Vậy ta nên cho phép các Tỳ Kheo—",
  "dn14:3.24.5": "này các Tỳ Kheo, hãy đi du hành, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người; ",
  "dn14:3.24.6": "đừng hai người đi cùng một đường; ",
  "dn14:3.24.7": "này các Tỳ Kheo, hãy thuyết pháp sơ thiện, trung thiện, hậu thiện, đầy đủ ý nghĩa và văn cú, hãy trình bày đời sống phạm hạnh hoàn toàn viên mãn, thanh tịnh. ",
  "dn14:3.24.8": "Có những chúng sinh ít nhiễm cấu, nếu không nghe pháp họ sẽ bị hư hoại, sẽ có những người hiểu được pháp. ",
  "dn14:3.24.9": "Tuy nhiên, cứ mỗi sáu năm, phải đến kinh đô Bandhumatī để tụng đọc giới bổn.”’ ",
  "dn14:3.25.1": "Rồi này các Tỳ Kheo, có một vị Đại Phạm Thiên khác với tâm mình biết được suy nghĩ trong tâm của ta, ví như một người lực sĩ co duỗi cánh tay, hay duỗi co cánh tay; cũng vậy—biến mất khỏi cõi Phạm thiên và xuất hiện trước mặt ta. ",
  "dn14:3.25.2": "Rồi này các Tỳ Kheo, vị Đại Phạm Thiên ấy vắt y thượng lên một vai, chắp tay hướng về phía ta và nói với ta: ",
  "dn14:3.25.3": "‘Đúng vậy, Bạch Thế Tôn, đúng vậy, Bạch Thiện Thệ. ",
  "dn14:3.25.4": "Bạch Thế Tôn, hiện nay đại chúng Tỳ Kheo sáu triệu tám trăm ngàn vị đang cư trú tại kinh đô Bandhumatī. ",
  "dn14:3.25.5": "Xin Thế Tôn cho phép các Tỳ Kheo—",
  "dn14:3.25.6": "này các Tỳ Kheo, hãy đi du hành, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người; ",
  "dn14:3.25.7": "đừng hai người đi cùng một đường; ",
  "dn14:3.25.8": "này các Tỳ Kheo, hãy thuyết pháp …(v.v.)… ",
  "dn14:3.25.9": "có những chúng sinh ít nhiễm cấu, nếu không nghe pháp họ sẽ bị hư hoại, sẽ có những người hiểu được pháp. ",
  "dn14:3.25.10": "Còn Bạch Thế Tôn, chúng con sẽ làm sao cho các Tỳ Kheo cứ mỗi sáu năm đều đến kinh đô Bandhumatī để tụng đọc giới bổn.’ ",
  "dn14:3.25.11": "Này các Tỳ Kheo, vị Đại Phạm Thiên ấy đã nói như vậy. ",
  "dn14:3.25.12": "Sau khi nói xong, đảnh lễ ta, đi nhiễu bên phải rồi biến mất ngay tại đó. ",
  "dn14:3.26.1": "‘Này các Tỳ Kheo, Ta cho phép, hãy đi du hành, vì lợi ích cho nhiều người, vì hạnh phúc cho nhiều người, vì lòng thương xót thế gian, vì lợi ích, vì hạnh phúc, vì an lạc cho chư thiên và loài người; ",
  "dn14:3.26.2": "đừng hai người đi cùng một đường; ",
  "dn14:3.26.3": "này các Tỳ Kheo, hãy thuyết pháp sơ thiện, trung thiện, hậu thiện, đầy đủ ý nghĩa và văn cú, hãy trình bày đời sống phạm hạnh hoàn toàn viên mãn, thanh tịnh. ",
  "dn14:3.26.4": "Có những chúng sinh ít nhiễm cấu, nếu không nghe pháp họ sẽ bị hư hoại, ",
  "dn14:3.26.5": "sẽ có những người hiểu được pháp. ",
  "dn14:3.26.6": "Tuy nhiên, này các Tỳ Kheo, cứ mỗi sáu năm, phải đến kinh đô Bandhumatī để tụng đọc giới bổn.’ ",
  "dn14:3.26.7": "Rồi này các Tỳ Kheo, phần lớn các Tỳ Kheo trong cùng một ngày đã đi du hành khắp các xứ. ",
  "dn14:3.27.1": "Lúc bấy giờ, ở châu Jambudīpa có tám mươi bốn ngàn trú xứ. ",
  "dn14:3.27.2": "Khi một năm đã trôi qua, chư thiên thông báo: ",
  "dn14:3.27.3": "‘Quý vị ơi, một năm đã trôi qua; ",
  "dn14:3.27.4": "còn lại năm năm; ",
  "dn14:3.27.5": "sau năm năm nữa phải đến kinh đô Bandhumatī để tụng đọc giới bổn.’ ",
  "dn14:3.27.6": "Khi hai năm đã trôi qua … ",
  "dn14:3.27.7": "khi ba năm đã trôi qua … ",
  "dn14:3.27.8": "khi bốn năm đã trôi qua … ",
  "dn14:3.27.9": "khi năm năm đã trôi qua, chư thiên thông báo: ",
  "dn14:3.27.10": "‘Quý vị ơi, năm năm đã trôi qua; ",
  "dn14:3.27.11": "còn lại một năm; ",
  "dn14:3.27.12": "sau một năm nữa phải đến kinh đô Bandhumatī để tụng đọc giới bổn.’ ",
  "dn14:3.27.13": "Khi sáu năm đã trôi qua, chư thiên thông báo: ",
  "dn14:3.27.14": "‘Quý vị ơi, sáu năm đã trôi qua, ",
  "dn14:3.27.15": "nay đã đến lúc phải đến kinh đô Bandhumatī để tụng đọc giới bổn.’ ",
  "dn14:3.27.16": "Rồi này các Tỳ Kheo, các Tỳ Kheo ấy, một số bằng thần lực của mình, một số bằng thần lực của chư thiên, trong cùng một ngày đã đến kinh đô Bandhumatī để tụng đọc giới bổn. ",
  "dn14:3.28.1": "Tại đó, này các Tỳ Kheo, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác tụng đọc giới bổn trong chúng Tỳ Kheo như sau: ",
  "dn14:3.28.2": "‘Nhẫn nại, khổ hạnh tối thượng, ",
  "dn14:3.28.3": "Niết-bàn tối thượng, chư Phật nói; ",
  "dn14:3.28.4": "Người xuất gia không làm hại người, ",
  "dn14:3.28.5": "Không phải Sa-môn nếu còn quấy nhiễu người. ",
  "dn14:3.28.6": "Không làm các điều ác, ",
  "dn14:3.28.7": "Thành tựu các hạnh lành; ",
  "dn14:3.28.8": "Giữ tâm ý trong sạch, ",
  "dn14:3.28.9": "Đó là lời chư Phật dạy. ",
  "dn14:3.28.10": "Không chỉ trích, không làm hại, ",
  "dn14:3.28.11": "Hộ trì theo giới bổn; ",
  "dn14:3.28.12": "Biết tiết độ trong ăn uống, ",
  "dn14:3.28.13": "Tìm nơi nằm nghỉ thanh vắng; ",
  "dn14:3.28.14": "Chuyên tâm vào thắng tâm, ",
  "dn14:3.28.15": "Đó là lời chư Phật dạy.’ ",
  "dn14:3.29.0": "17. Chư thiên thông báo ",
  "dn14:3.29.1": "Này các Tỳ Kheo, một thời Ta trú tại Ukkaṭṭhā, trong rừng Subhaga, dưới gốc cây sāla chúa. ",
  "dn14:3.29.2": "Khi Ta ở một mình nơi yên tĩnh, này các Tỳ Kheo, trong tâm Ta khởi lên ý nghĩ như sau: ",
  "dn14:3.29.3": "‘Không dễ gì có một cõi chúng sinh mà Ta đã không từng cư trú trong suốt thời gian dài này, ngoại trừ chư thiên cõi Tịnh Cư. ",
  "dn14:3.29.4": "Vậy Ta hãy đi đến chỗ chư thiên cõi Tịnh Cư.’ ",
  "dn14:3.29.5": "Rồi này các Tỳ Kheo, ví như một người lực sĩ co duỗi cánh tay, hay duỗi co cánh tay; cũng vậy—Ta biến mất khỏi Ukkaṭṭhā, khỏi rừng Subhaga, khỏi gốc cây sāla chúa và xuất hiện giữa chư thiên cõi Aviha. ",
  "dn14:3.29.6": "Này các Tỳ Kheo, trong cõi trời ấy, hàng ngàn, hàng trăm ngàn vị thần đã đi đến chỗ Ta; sau khi đến, họ đảnh lễ Ta rồi đứng một bên. Đứng một bên, này các Tỳ Kheo, các vị thần ấy thưa với Ta: ",
  "dn14:3.29.7": "‘Thưa tôn giả, cách đây chín mươi mốt kiếp, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:3.29.8": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:3.29.9": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña. ",
  "dn14:3.29.10": "Thưa tôn giả, thọ mạng của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác là tám mươi ngàn năm. ",
  "dn14:3.29.11": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Pāṭali. ",
  "dn14:3.29.12": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Khaṇḍa và Tissa là đệ tử tối thượng, thù thắng. ",
  "dn14:3.29.13": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có ba lần hội họp đệ tử. Một lần hội họp có sáu triệu tám trăm ngàn Tỳ Kheo. Một lần hội họp có một trăm ngàn Tỳ Kheo. Một lần hội họp có tám mươi ngàn Tỳ Kheo. Thưa tôn giả, đây là ba lần hội họp đệ tử của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:3.29.14": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Asoka là thị giả, thị giả tối thượng. ",
  "dn14:3.29.15": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có cha là vua tên Bandhuma. ",
  "dn14:3.29.16": "Mẹ sinh ra Ngài là hoàng hậu tên Bandhumatī. ",
  "dn14:3.29.17": "Kinh đô của vua Bandhuma là thành Bandhumatī. ",
  "dn14:3.29.18": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã xuất ly như vậy, đã xuất gia như vậy, đã nỗ lực như vậy, đã giác ngộ như vậy, đã chuyển Pháp luân như vậy. ",
  "dn14:3.29.19": "Thưa tôn giả, chúng con đã sống đời phạm hạnh dưới Thế Tôn Vipassī, đã đoạn trừ dục ái đối với các dục, và đã tái sinh ở đây.’ … ",
  "dn14:3.29.20": "(v.v.)… ",
  "dn14:3.30.1": "Cũng trong cõi trời ấy, này các Tỳ Kheo, hàng ngàn, hàng trăm ngàn vị thần đã đi đến chỗ Ta; sau khi đến, họ đảnh lễ Ta rồi đứng một bên. Đứng một bên, này các Tỳ Kheo, các vị thần ấy thưa với Ta: ",
  "dn14:3.30.2": "‘Thưa tôn giả, trong kiếp hiền này, nay Thế Tôn là bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:3.30.3": "Thưa tôn giả, Thế Tôn thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:3.30.4": "Thưa tôn giả, Thế Tôn thuộc họ Gotama. ",
  "dn14:3.30.5": "Thưa tôn giả, thọ mạng của Thế Tôn ngắn ngủi, ít ỏi, chóng qua; ai sống lâu thì cũng chỉ một trăm năm hoặc hơn chút ít. ",
  "dn14:3.30.6": "Thưa tôn giả, Thế Tôn chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Assattha. ",
  "dn14:3.30.7": "Thưa tôn giả, Thế Tôn có hai vị đệ tử tên Sāriputta và Moggallāna là đệ tử tối thượng, thù thắng. ",
  "dn14:3.30.8": "Thưa tôn giả, Thế Tôn có một lần hội họp đệ tử gồm một ngàn hai trăm năm mươi Tỳ Kheo. Thưa tôn giả, đây là một lần hội họp đệ tử của Thế Tôn, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:3.30.9": "Thưa tôn giả, Thế Tôn có vị Tỳ Kheo tên Ānanda là thị giả, thị giả tối thượng. ",
  "dn14:3.30.10": "Thưa tôn giả, Thế Tôn có cha là vua tên Suddhodana. ",
  "dn14:3.30.11": "Mẹ sinh ra Ngài là hoàng hậu tên Māyā. ",
  "dn14:3.30.12": "Kinh đô là thành Kapilavatthu. ",
  "dn14:3.30.13": "Thưa tôn giả, Thế Tôn đã xuất ly như vậy, đã xuất gia như vậy, đã nỗ lực như vậy, đã giác ngộ như vậy, đã chuyển Pháp luân như vậy. ",
  "dn14:3.30.14": "Thưa tôn giả, chúng con đã sống đời phạm hạnh dưới Thế Tôn, đã đoạn trừ dục ái đối với các dục, và đã tái sinh ở đây.’ ",
  "dn14:3.31.1": "Rồi này các Tỳ Kheo, Ta cùng với chư thiên cõi Aviha đi đến chỗ chư thiên cõi Atappa …(v.v.)… ",
  "dn14:3.31.2": "rồi này các Tỳ Kheo, Ta cùng với chư thiên cõi Aviha và chư thiên cõi Atappa đi đến chỗ chư thiên cõi Sudassa. ",
  "dn14:3.31.3": "Rồi này các Tỳ Kheo, Ta cùng với chư thiên cõi Aviha, chư thiên cõi Atappa và chư thiên cõi Sudassa đi đến chỗ chư thiên cõi Sudassī. Rồi này các Tỳ Kheo, Ta cùng với chư thiên cõi Aviha, chư thiên cõi Atappa, chư thiên cõi Sudassa và chư thiên cõi Sudassī đi đến chỗ chư thiên cõi Akaniṭṭha. Này các Tỳ Kheo, trong cõi trời ấy, hàng ngàn, hàng trăm ngàn vị thần đã đi đến chỗ Ta, sau khi đến, họ đảnh lễ Ta rồi đứng một bên. Đứng một bên, này các Tỳ Kheo, các vị thần ấy thưa với Ta: ",
  "dn14:3.31.4": "‘Thưa tôn giả, cách đây chín mươi mốt kiếp, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:3.31.5": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc dòng dõi Sát-đế-lỵ. ",
  "dn14:3.31.6": "Sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:3.31.7": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác thuộc họ Koṇḍañña. ",
  "dn14:3.31.8": "Thưa tôn giả, thọ mạng của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác là tám mươi ngàn năm. ",
  "dn14:3.31.9": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Pāṭali. ",
  "dn14:3.31.10": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có hai vị đệ tử tên Khaṇḍa và Tissa là đệ tử tối thượng, thù thắng. ",
  "dn14:3.31.11": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có ba lần hội họp đệ tử. ",
  "dn14:3.31.12": "Một lần hội họp có sáu triệu tám trăm ngàn Tỳ Kheo. ",
  "dn14:3.31.13": "Một lần hội họp có một trăm ngàn Tỳ Kheo. ",
  "dn14:3.31.14": "Một lần hội họp có tám mươi ngàn Tỳ Kheo. ",
  "dn14:3.31.15": "Thưa tôn giả, đây là ba lần hội họp đệ tử của Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:3.31.16": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có vị Tỳ Kheo tên Asoka là thị giả, thị giả tối thượng. ",
  "dn14:3.31.17": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác có cha là vua tên Bandhuma, mẹ sinh ra Ngài là hoàng hậu tên Bandhumatī. ",
  "dn14:3.31.18": "Kinh đô của vua Bandhuma là thành Bandhumatī. ",
  "dn14:3.31.19": "Thưa tôn giả, Thế Tôn Vipassī, bậc A-la-hán, Chánh Đẳng Giác đã xuất ly như vậy, đã xuất gia như vậy, đã nỗ lực như vậy, đã giác ngộ như vậy, đã chuyển Pháp luân như vậy. ",
  "dn14:3.31.20": "Thưa tôn giả, chúng con đã sống đời phạm hạnh dưới Thế Tôn Vipassī, đã đoạn trừ dục ái đối với các dục, và đã tái sinh ở đây.’ ",
  "dn14:3.31.21": "Cũng trong cõi trời ấy, này các Tỳ Kheo, hàng ngàn, hàng trăm ngàn vị thần đã đi đến chỗ Ta; sau khi đến, họ đảnh lễ Ta rồi đứng một bên. Đứng một bên, này các Tỳ Kheo, các vị thần ấy thưa với Ta: ",
  "dn14:3.31.22": "‘Thưa tôn giả, cách đây ba mươi mốt kiếp, Thế Tôn Sikhī …(v.v.)… ",
  "dn14:3.31.23": "chúng con, thưa tôn giả, đã sống dưới Thế Tôn Sikhī; và cũng trong ba mươi mốt kiếp ấy, thưa tôn giả, Thế Tôn Vessabhū …(v.v.)… ",
  "dn14:3.31.24": "chúng con, thưa tôn giả, đã sống dưới Thế Tôn Vessabhū …(v.v.)… ",
  "dn14:3.31.25": "Trong chính kiếp hiền này, thưa tôn giả, các Thế Tôn Kakusandha, Koṇāgamana, Kassapa …(v.v.)… ",
  "dn14:3.31.26": "chúng con, thưa tôn giả, đã sống đời phạm hạnh dưới các Thế Tôn Kakusandha, Koṇāgamana, Kassapa, đã đoạn trừ dục ái đối với các dục, và đã tái sinh ở đây.’ ",
  "dn14:3.32.1": "Cũng trong cõi trời ấy, này các Tỳ Kheo, hàng ngàn, hàng trăm ngàn vị thần đã đi đến chỗ Ta; sau khi đến, họ đảnh lễ Ta rồi đứng một bên. Đứng một bên, này các Tỳ Kheo, các vị thần ấy thưa với Ta: ",
  "dn14:3.32.2": "‘Thưa tôn giả, trong kiếp hiền này, nay Thế Tôn là bậc A-la-hán, Chánh Đẳng Giác đã xuất hiện ở đời. ",
  "dn14:3.32.3": "Thưa tôn giả, Thế Tôn thuộc dòng dõi Sát-đế-lỵ, sinh trong gia đình Sát-đế-lỵ. ",
  "dn14:3.32.4": "Thưa tôn giả, Thế Tôn thuộc họ Gotama. ",
  "dn14:3.32.5": "Thưa tôn giả, thọ mạng của Thế Tôn ngắn ngủi, ít ỏi, chóng qua, ai sống lâu thì cũng chỉ một trăm năm hoặc hơn chút ít. ",
  "dn14:3.32.6": "Thưa tôn giả, Thế Tôn chứng đắc Vô Thượng Chánh Đẳng Giác dưới cây Assattha. ",
  "dn14:3.32.7": "Thưa tôn giả, Thế Tôn có hai vị đệ tử tên Sāriputta và Moggallāna là đệ tử tối thượng, thù thắng. ",
  "dn14:3.32.8": "Thưa tôn giả, Thế Tôn có một lần hội họp đệ tử gồm một ngàn hai trăm năm mươi Tỳ Kheo. ",
  "dn14:3.32.9": "Thưa tôn giả, đây là một lần hội họp đệ tử của Thế Tôn, tất cả đều là bậc đoạn tận lậu hoặc. ",
  "dn14:3.32.10": "Thưa tôn giả, Thế Tôn có vị Tỳ Kheo tên Ānanda là thị giả, thị giả tối thượng. ",
  "dn14:3.32.11": "Thưa tôn giả, Thế Tôn có cha là vua tên Suddhodana. ",
  "dn14:3.32.12": "Mẹ sinh ra Ngài là hoàng hậu tên Māyā. ",
  "dn14:3.32.13": "Kinh đô là thành Kapilavatthu. ",
  "dn14:3.32.14": "Thưa tôn giả, Thế Tôn đã xuất ly như vậy, đã xuất gia như vậy, đã nỗ lực như vậy, đã giác ngộ như vậy, đã chuyển Pháp luân như vậy. ",
  "dn14:3.32.15": "Thưa tôn giả, chúng con đã sống đời phạm hạnh dưới Thế Tôn, đã đoạn trừ dục ái đối với các dục, và đã tái sinh ở đây.’ ",
  "dn14:3.33.1": "Như vậy, này các Tỳ Kheo, đây chính là pháp giới mà Như Lai đã khéo thông đạt, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ‘Các Thế Tôn ấy có dòng sinh như vậy.’ ",
  "dn14:3.33.2": "‘Có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy.’ ",
  "dn14:3.33.3": "Chư thiên cũng báo cho Như Lai biết điều ấy, do đó Như Lai nhớ lại các vị Phật quá khứ đã nhập Niết-bàn, đã đoạn tận hý luận, đã cắt đứt con đường luân hồi, đã chấm dứt vòng luân hồi, đã vượt qua mọi khổ đau, Ngài nhớ lại cả sự sinh của họ, nhớ lại cả tên của họ, nhớ lại cả dòng họ của họ, nhớ lại cả thọ mạng của họ, nhớ lại cả hai vị đệ tử tối thượng của họ, nhớ lại cả số lần hội họp đệ tử của họ: ‘Các Thế Tôn ấy có dòng sinh như vậy.’ ",
  "dn14:3.33.4": "‘Có tên như vậy, có dòng họ như vậy, có giới đức như vậy, có pháp như vậy, có tuệ như vậy, có đời sống như vậy, có sự giải thoát như vậy.’” ",
  "dn14:3.33.5": "Thế Tôn đã nói như vậy. ",
  "dn14:3.33.6": "Các Tỳ Kheo ấy hoan hỷ, tín thọ lời Thế Tôn dạy. ",
  "dn14:3.33.7": "Kinh Đại Bổn thứ nhất đã kết thúc. "
}
